INSERT INTO public.photos VALUES (23823, 'Calle de Goicoechea aâ”œâ–’os 30', 'Dibujo de Ambrosio Ruste de la calle de Goicoechea de Zaragoza (al fondo) vista desde el Pasaje de la industria y el Comercio. Las "escalericas del Pilar" bajan hasta la calle de Forment. Fuente visual: â”¬Ã­Aquâ”œÂ¡... Zaragoza", Josâ”œÂ® Blasco Ijazo, 1950.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65579800, -0.87834900, '0101000020E6100000802DAF5C6F1BECBF1F645930F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19810448578.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19810448578.webp', 'https://www.flickr.com/photos/zaragozaantigua/19810448578/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23824, 'Elefantes en el Ayuntamiento 1966', 'Desfile circense de elefantes ante el edificio del Ayuntamiento de Zaragoza en la plaza del Pilar, un aâ”œâ–’o despuâ”œÂ®s de su inauguraciâ”œâ”‚n. Fuente: www.facebook.com/photo.php?fbid=1072998256062443&set=...', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65580600, -0.87756600, '0101000020E6100000F19BC24A0515ECBFA2427573F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20089378261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20089378261.webp', 'https://www.flickr.com/photos/zaragozaantigua/20089378261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23829, 'Calle del Pilar aâ”œâ–’os 30', 'Calle del Pilar. En el centro, verja del palacio de los marqueses de Ayerbe. A la derecha, la Lonja. Fuente: www.facebook.com/photo.php?fbid=10203611134318762&set...', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65584700, -0.87717800, '0101000020E61000007AA9D898D711ECBF011764CBF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21105527093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21105527093.webp', 'https://www.flickr.com/photos/zaragozaantigua/21105527093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23836, 'Plaza del Pilar 1955', '"Plaza del Pilar. Ayuntamiento. Basâ”œÂ¡lica de Nuestra Seâ”œâ–’ora del Pilar. Jardines. Farolas". El ciclo vital de los efemerâ”œâ”‚pteros, en su fase de insecto volador, es de menos de un dâ”œÂ¡a de duraciâ”œâ”‚n. Para ellos, "toda la vida imaginable" es un largo lapso de apenas 24 horas. Una peculiar caracterâ”œÂ¡stica de los indâ”œÂ¡genas de esta ciudad preserva esta distintiva distorsiâ”œâ”‚n temporal desde los antiguos tiempos de nuestra etapa evolutiva como insectos, y la condensa en la popular y sâ”œâ”‚lidamente arraigada expresiâ”œâ”‚n "esto es asâ”œÂ¡ de toda la vida". En la imagen, son los mediados de los aâ”œâ–’os 50 del pasado siglo. Nos separan de ella apenas sesenta de los mâ”œÃ­s de 2000 aâ”œâ–’os de "historia" de esta ciudad, y nos encontramos con que la "tradicional" plaza del Pilar sigue en construcciâ”œâ”‚n. A la izquierda, el nuevo edificio del Gobierno Civil ha sido terminado ha poco. A la derecha, la nueva Casa Consistorial continâ”œâ•‘a en obras. A la recientâ”œÂ¡sima nueva fachada del Pilar aâ”œâ•‘n le faltan 14 aâ”œâ–’os para contener la escultura-retablo de Pablo Serrano de la virgen encolumnada, y las torres de la cara ribereâ”œâ–’a del templo, prosiguen su laboriosa trama. Al fondo, el monumento "A los hâ”œÂ®roes y mâ”œÃ­rtires de Zaragoza. Caâ”œÂ¡dos en la Cruzada de Liberaciâ”œâ”‚n 1936-1939", ha sido inaugurado hace poco, y el solar donde se proyecta levantar los "Juzgados y Magistratura de Trabajo de Zaragoza", seguirâ”œÃ­ asâ”œÂ¡ unos aâ”œâ–’os aâ”œâ•‘n. Por no existir, no existe ni la "tradicional" ofrenda de flores: faltan tres aâ”œâ–’os para que sea "inventada", como local reformulaciâ”œâ”‚n de lo que ya venâ”œÂ¡a haciâ”œÂ®ndose en otros sitios. "O tempora, o mores". Fuente visual: Archivo Coyne (DARA-AHPZ).', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65580600, -0.87756600, '0101000020E6100000F19BC24A0515ECBFA2427573F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22892412665.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22892412665.webp', 'https://www.flickr.com/photos/zaragozaantigua/22892412665/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23846, 'Vuelta ciclista 1965', 'El corredor Josâ”œÂ® Martâ”œÂ¡n Colmenarejo ganâ”œâ”‚ la 13â”¬Â¬ etapa (Lâ”œÂ®rida-Zaragoza) de la Vuelta ciclista a Espaâ”œâ–’a 1965. En la imagen, llegada del mâ”œÂ¡tico Federico Martâ”œÂ¡n Bahamontes, entonces en el equipo "Inuri - Margnat", en su â”œâ•‘ltimo aâ”œâ–’o como corredor profesional. Terminâ”œâ”‚ esta carrera en la posiciâ”œâ”‚n 10 de la clasificaciâ”œâ”‚n general. Al fondo, la torre de la Seo. Fuente: Agencia EFE.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65588700, -0.87781100, '0101000020E6100000B53522180717ECBF8F6FEF1AF4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24533529201.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24533529201.webp', 'https://www.flickr.com/photos/zaragozaantigua/24533529201/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23852, 'Plaza del Pilar 1987', 'Imagen de la plaza del Pilar capturada desde la replaceta del Gobierno Civil. En primer plano, el "templete" de la Oficina Municipal de Turismo, que pretendâ”œÂ¡a rememorar al postmoderno gusto de la "movida", el original templo romano cuyos restos quedaron destruidos al construirse los garajes subterrâ”œÃ­neos que estâ”œÃ­n justo debajo. Luego vendrâ”œÂ¡an las recreaciones 3-D de la Zaragoza romana, y otras inimaginables aplicaciones en el momento de la imagen. Fuente visual: www.flickr.com/photos/30957604@N06/12235618614/in/photoli...', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65564100, -0.87818600, '0101000020E610000005C3B986191AECBF5875560BECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27098587790.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27098587790.webp', 'https://www.flickr.com/photos/zaragozaantigua/27098587790/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23854, 'Plaza del Pilar 1955', 'Las obras del nuevo ayuntamiento progresaban a un ritmo tranquilo, y ya casi habâ”œÂ¡a transcurrido una dâ”œÂ®cada desde que en 1946 se pusiera oficialmente la primera piedra. A la izquierda, los caâ”œâ–’izos del andamiaje indican que el trabajo continâ”œâ•‘a en la parte mâ”œÃ­s prâ”œâ”‚xima al paseo de Echegaray y Caballero. Mientras tanto, su fachada principal aparece casi terminada, si bien todavâ”œÂ¡a sin los iconos protectores de la ciudad que aâ”œâ–’os despuâ”œÂ®s flanquearâ”œÂ¡an la puerta de acceso. Mientras tanto, la Casa Consistorial continuaba funcionalmente radicada en la plaza de Santo Domingo. Sobre la despejada y gran plaza de las Catedrales se destacan algunos elementos decorativos para dar siquiera algo de color y vida a tanto metro cuadrado de dura superficie. Al fondo, la plaza de La Seo y su isleta de verdor. Esta captura fue realizada por el fotâ”œâ”‚grafo francâ”œÂ®s Jean Paul Margnac en el verano de 1955, durante su paso por la penâ”œÂ¡nsula Ibâ”œÂ®rica, desde Parâ”œÂ¡s, y con destino hacia tierras mâ”œÃ­s meridionales. Fuente visual: www.flickr.com/photos/jean-paul-margnac/11012390964/in/al...', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65580600, -0.87756600, '0101000020E6100000F19BC24A0515ECBFA2427573F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27208679602.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27208679602.webp', 'https://www.flickr.com/photos/zaragozaantigua/27208679602/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23861, 'Plaza del Pilar 1967', 'Imagen capturada durante la encabalgada lectura del pregâ”œâ”‚n de las fiestas mayores de Zaragoza, a cargo de su "pregonero mayor", Ignacio Moreno Bregante, disfrazado a la carpetovetâ”œâ”‚nica usanza de esa Edad Media pasada por el vestuario ye-ye de la venganza de don Mendo, y a juego con el resto de figurantes municipales. Autoridades y nutrido pâ”œâ•‘blico a la escucha, en una escenificaciâ”œâ”‚n localizada delante del nuevo edificio consistorial. A la izquierda, el nuevo edificio del Gobierno Civil. Al fondo, el elevado y recayente tramo de la calle de Santiago, con los antiguos edificios habitacionales que lo caracterizaban. Fuente visual: Gerardo Sancho Ramo, AMZ', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65573400, -0.87796300, '0101000020E6100000362383DC4518ECBF09707A17EFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29854200360.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29854200360.webp', 'https://www.flickr.com/photos/zaragozaantigua/29854200360/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23863, 'Pl. del Pilar 1954', 'Imagen durante el derribo de la antigua manzana de casas ubicada entre las calles de Santiago, al fondo, Bayeu, a la izquierda, Forment, a la derecha, y la desaparecida calle de Juan Martâ”œÂ¡n Goicoechea, en primer plano, antigua del Horno de la Caraza. Los restos de esta fachada pertenecâ”œÂ¡an, precisamente, a la casa de este Goicoechea, un destacado prâ”œâ”‚cer local (de adopciâ”œâ”‚n) de la segunda mitad del luminoso siglo XVIII. El derribo de esta antigua manzana de casas supuso la desapariciâ”œâ”‚n del â”œâ•‘ltimo tramo de esta calle-fâ”œâ”‚sil, y el derribo de la referida gran casona, con todos los elementos edilicios acompaâ”œâ–’antes. La presencia del nuevo edificio sede del Gobernador Civil, a la izquierda, justificâ”œâ”‚ entonces el derribo y allanamiento de esta manzana, cuyo solar dejâ”œâ”‚ una nueva replaceta, como acompaâ”œâ–’amiento a la necesaria gran plaza del Pilar. De rebote, un tramo de la calle de Santiago se convirtiâ”œâ”‚, sin pretenderlo, en provisional nueva fachada a esta gran plaza del Pilar. Provisional, pues hasta aquâ”œÂ¡ estuvo diseâ”œâ–’ado prolongar el paseo de la Independencia, llevâ”œÃ­ndose por delante lo que hubiera, o hubiese, tal como se hizo unos aâ”œâ–’os antes con la calle de San Vicente de Paâ”œâ•‘l. Fuente visual: Josâ”œÂ® Ignacio Gâ”œâ”‚mez Zorraquino, "Los Goicoechea y su interâ”œÂ®s por la tierra y el agua en el Aragâ”œâ”‚n del siglo XVIII", DGA, 1989.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65547300, -0.87811100, '0101000020E61000005B40683D7C19ECBF9C340D8AE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30147416835.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30147416835.webp', 'https://www.flickr.com/photos/zaragozaantigua/30147416835/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23882, 'Pl. del Pilar 1954', 'Imagen capturada durante el derribo de la antigua manzana de casas ubicada entre las calles de Santiago, Bayeu, Forment, y la de Juan Martâ”œÂ¡n Goicoechea. Los restos de la fachada pertenecâ”œÂ¡an a la casona familiar de Juan Goicoechea, destacado prâ”œâ”‚cer local (de adopciâ”œâ”‚n) durante la segunda mitad del luminoso siglo XVIII. El derribo estaba justificado para dar espacio al nuevo edificio, a la izquierda, del Gobierno Civil, y porque este era el tramo final del prolongado paseo de la Independencia, que hasta aquâ”œÂ¡ deberâ”œÂ¡a haber llegado, en lâ”œÂ¡nea recta desde la plaza de Espaâ”œâ–’a. Cuando este delirio no fue acometido, quedâ”œâ”‚ una linda replaceta dura. En la imagen, visita oficial de inspecciâ”œâ”‚n de obra. Entre los notables, el alcalde Luis Gâ”œâ”‚mez Laguna, y el jefe del Movimiento Nacional y Gobernador Civil de Zaragoza, Josâ”œÂ® Manuel Pardo de Santayana. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65547300, -0.87811100, '0101000020E61000005B40683D7C19ECBF9C340D8AE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31533505165.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31533505165.webp', 'https://www.flickr.com/photos/zaragozaantigua/31533505165/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23907, 'Plaza del Pilar c.1942', 'Despejada imagen capturada en la nueva plaza del Pilar resultante del derribo de las manzanas de viviendas del oriente de la antigua plaza, entre las calles del Pilar y de Goicoechea, y entre las de Damiâ”œÃ­n Forment y Don Jaime I. A la derecha, inmuebles del lado de los impares de la antigua calle del Pilar entre la Lonja y el homâ”œâ”‚nimo templo, que poco despuâ”œÂ®s serâ”œÂ¡an derribados para dejar paso a la nueva Casa Consistorial.', 1942, 1942, 1942, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65569500, -0.87761800, '0101000020E610000090300C587215ECBF4B9352D0EDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51410527146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51410527146.webp', 'https://www.flickr.com/photos/zaragozaantigua/51410527146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23912, 'Plaza del Pilar c.1968', 'Imagen capturada en la plaza del Pilar con un turâ”œÂ¡stico posado ante el monumento a Goya inaugurado en 1960 en la zona inmediata a la Lonja. Justo tras ellos destaca el cenotafio de Goya que hasta esa fecha habâ”œÂ¡a estado ubicado en el Rincâ”œâ”‚n de Goya del parque del General Primo de Rivera. Como impresionante telâ”œâ”‚n de fondo, la barroca torre de La Seo del Salvador en su Epifanâ”œÂ¡a que se alza desde la plaza homâ”œâ”‚nima, donde a la izquierda, a la altura del Cine Pax, aparece estacionado un tranvâ”œÂ¡a articulado de la serie 250 en servicio en la lâ”œÂ¡nea 10 "Academia", lâ”œÂ¡nea que serâ”œÂ¡a clausurada en enero de 1971, y este tranvâ”œÂ¡a desguazado poco despuâ”œÂ®s. Durante las obras de reforma de la plaza en 1990 este entorno fue modificado sustancialmente.', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65560700, -0.87710300, '0101000020E6100000D026874F3A11ECBFAC0320EEEAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53274149940.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53274149940.webp', 'https://www.flickr.com/photos/zaragozaantigua/53274149940/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24080, 'Calle de Espoz y Mina 1937', 'Imagen capturada desde el inmueble del nâ”¬â•‘ 51-55 de la calle de Espoz y Mina y centrada en los destrozos ocasionados en el inmueble del nâ”¬â•‘ 44-46 de esa misma calle, con el que confrontaba. El dâ”œÂ¡a 3 de mayo de 1937, a las 18:30 h, una bomba de aviaciâ”œâ”‚n de la Fuerzas Aâ”œÂ®reas de la Repâ”œâ•‘blica Espaâ”œâ–’ola impactâ”œâ”‚ directamente en â”œÂ®l. Otra bomba cayâ”œâ”‚ en las inmediaciones. El resultado fue espantoso: un centenar de heridos y muertos. Esta casa conservaba hasta 2021 una placa memorialista referida a este terrible suceso, incrustada en los azulejos restaurados de primer tâ”œÂ®rmino y a la derecha. Al fondo y a la izquierda sobresale la câ”œâ•‘pula del Banco Zaragozano. A la derecha, tejado y palomar del inmueble del nâ”¬â•‘ 1 de la plaza de la Constituciâ”œâ”‚n esquinero con el Coso Alto.', 1937, 1937, 1937, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65426800, -0.87783300, '0101000020E6100000A92F4B3B3517ECBFE068C70DBFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38667937795.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38667937795.webp', 'https://www.flickr.com/photos/zaragozaantigua/38667937795/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24120, 'Plaza de Ariâ”œâ–’o 1916', 'Imagen capturada en la plaza de Ariâ”œâ–’o durante la estancia en la ciudad de una excursiâ”œâ”‚n comercial easonense, con un posado colectivo de estos donostiarras donde destacan los alcaldes de San Sebastiâ”œÃ­n (Eustaquio Inciarte Alday) y de Zaragoza (Josâ”œÂ® Salarrullana de Dios).', 1916, 1916, 1916, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65381100, -0.87817600, '0101000020E6100000213A048E041AECBFED612F14B0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53502083913.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53502083913.webp', 'https://www.flickr.com/photos/zaragozaantigua/53502083913/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24483, 'Calle de Santiago c.1964', 'Foto: Colecciâ”œâ”‚n Jesâ”œâ•‘s Cortâ”œÂ®s Soler. Chaflâ”œÃ­n de las calles de Santiago (derecha) y Damiâ”œÃ­n Forment, sede de la Churrerâ”œÂ¡a del Pilar, en el antiguo nâ”¬â•‘ 9 de la calle de Santiago. El edificio fue derribado mâ”œÃ­s tarde para completar el despeje de la recoleta zona de la plaza del Pilar frente a la fachada principal del Gobierno civil.', 1964, 1964, 1964, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65540300, -0.87857300, '0101000020E610000066C1C41F451DECBFA359D93EE4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23554773098.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23554773098.webp', 'https://www.flickr.com/photos/zaragozaantigua/23554773098/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24602, 'Plaza del Pilar 1990', 'Imagen de las obras de rehabilitaciâ”œâ”‚n y embellecimiento de la plaza del Pilar capturada durante la construcciâ”œâ”‚n del aparcamiento inmediato al Ayuntamiento y el edificio del Gobierno Civil. En el centro de la escena luce reciâ”œÂ®n restaurada la Lonja. A la derecha y al fondo, la plaza de La Seo en obras, destacando su fachada neoclâ”œÃ­sica embutida en andamios y lonas durante las tareas de limpieza y restauraciâ”œâ”‚n.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65583100, -0.87770400, '0101000020E61000003430F2B22616ECBFFB592C45F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50458743651.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50458743651.webp', 'https://www.flickr.com/photos/zaragozaantigua/50458743651/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24657, 'Plaza del Pilar c.1943', 'Imagen capturada en el tramo mâ”œÃ­s oriental de la ampliada plaza del Pilar, con el telâ”œâ”‚n del fondo de la plaza de La Seo. A la izquierda, vista parcial del antiguo inmueble del nâ”¬â•‘ 17 de la calle del Pilar, seguido del nâ”¬â•‘ 19 de esas misma calle que ya estâ”œÃ­ en proceso de derribo, antes de la Lonja. Sobre los solares de estos inmuebles derribados y por derribar, entre otros, estaba proyectada la construcciâ”œâ”‚n de la nueva Casa Consistorial. A la derecha, gran solar sobre el que estaba proyectado construir, entre otros edificios, la nueva sede del Gobierno Civil.', 1943, 1943, 1943, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65572700, -0.87711400, '0101000020E6100000CAA31B615111ECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49213554541.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49213554541.webp', 'https://www.flickr.com/photos/zaragozaantigua/49213554541/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25064, 'San Valero 1965', 'Archivo Ayuntamiento de Zaragoza/Gerardo Sancho, 1965. Valero de Zaragoza fue un obispo de la ciudad que viviâ”œâ”‚ en el siglo IV. Fue maestro de San Vicente Mâ”œÃ­rtir y es el patrâ”œâ”‚n de Zaragoza. Su festividad se celebra el 29 de enero comiendo roscâ”œâ”‚n. Los zaragozanos acuden a La Seo para venerar sus reliquias y desde hace unos aâ”œâ–’os para aprovechar que es el â”œâ•‘nico dâ”œÂ¡a que se accede gratis a la catedral. El dicho popular "San Valero, ventolero" alude al famoso cierzo de la ciudad, que por esas fechas se despliega con fuerza. En la foto, estatua en bronce fundido del santo, obra de Pablo Serrano, reciâ”œÂ®n colocada dos dâ”œÂ¡as antes junto a la puerta del Ayuntamiento (22 de junio de 1965). En primer plano, el pedestal para situar la estatua del â”œÃ¼ngel de la Ciudad, que tendrâ”œÃ­ que esperar hasta el 10 de septiembre. Al fondo, el monumento a Goya y La Seo. Mâ”œÃ­s informaciâ”œâ”‚n: www.zaragoza.es/ciudad/artepublico/detalle_ArtePublico?id...', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65591000, -0.87748500, '0101000020E6100000BF60376C5B14ECBF478FDFDBF4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15002536010.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15002536010.webp', 'https://www.flickr.com/photos/zaragozaantigua/15002536010/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25139, 'Calle Espoz y Mina, 1983', 'Imagen de la medianera del Colegio Oficial de Arquitectos de Aragâ”œâ”‚n (antiguo palacio de los Torrero), pintada por Josâ”œÂ® Luis Lasala en 1977 como parte del proceso de rehabilitaciâ”œâ”‚n del edificio, cuando esta trasera era visible desde la calle Espoz y Mina, al objeto de mejorar estâ”œÂ®ticamente el entorno, esta vez sin el componente de denuncia social que se estaba dando en otras zonas degradadas de la ciudad. Aun en tiempos de notable agitaciâ”œâ”‚n socio-polâ”œÂ¡tica (finales de los aâ”œâ–’os 70), cuando el patrono (aunque no pagara) era una instituciâ”œâ”‚n, el esteticismo siempre encuentra formas de prevalecer sobre otros -ismos mâ”œÃ­s radicales, por menos molesto. Es lo que tiene la abstracciâ”œâ”‚n. Lasala (componente de la agrupaciâ”œâ”‚n "Azuda 40", junto con Baquâ”œÂ®, Bayo, Cano, Fortâ”œâ•‘n...), resolviâ”œâ”‚ con una abstracciâ”œâ”‚n geomâ”œÂ®trica y colorista este mural, inmediato a un solar con la iglesia de la Santa Cruz, a la derecha, y el solar del nâ”¬â•‘ 24 de la calle Espoz y Mina (ya construido, a la izquierda). Mâ”œÃ­s tarde, los pequeâ”œâ–’os solares de los nâ”œâ•‘meros 20 y 22 serâ”œÂ¡an construidos, y esta intervenciâ”œâ”‚n pictâ”œâ”‚rica, eclipsada. Fuente: Marâ”œÂ¡a Luisa Grau Tello, "La pintura mural en la esfera pâ”œâ•‘blica de Zaragoza".', 1983, 1983, 1983, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65488000, -0.87795000, '0101000020E61000000EBE30992A18ECBFF9669B1BD3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22341970502.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22341970502.webp', 'https://www.flickr.com/photos/zaragozaantigua/22341970502/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25164, 'Palacio de los Pardo aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste. Patio de la casa Aguilar o palacio de los Pardo, en la calle de Espoz y Mina. Fuente: Lâ”œÃ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65472200, -0.87827500, '0101000020E6100000ED9E3C2CD41AECBF61FC34EECDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32289462012.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32289462012.webp', 'https://www.flickr.com/photos/zaragozaantigua/32289462012/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25649, 'Iglesia de Santiago 1874', 'Interior de la iglesia de Santiago de Zaragoza, dibujo a tinta y aguada anâ”œâ”‚nimo, 1874. "Estaba muy cerca de la catedral del Salvador (La Seo) de la que era filial. Situada en la esquina de la actual calle que conserva el nombre del templo (antes denominada Sombrererâ”œÂ¡a) y los actuales nâ”œâ•‘meros 39 y 41 de la de Don Jaime I (antes Cuchillerâ”œÂ¡a). En esta â”œâ•‘ltima casa se conserva un relieve recordatorio con la cruz de Santiago y la imagen del santo en el interior. Era una iglesia relativamente pequeâ”œâ–’a, con elementos decorativos româ”œÃ­nicos de gran valor. La entrada se hacâ”œÂ¡a por la actual calle de Santiago, mientras que el â”œÃ­bside daba a Don Jaime . Aunque en una rehabilitaciâ”œâ”‚n posterior, se rectifica y la entrada se coloca por D. Jaime. En el â”œâ•‘ltimo cuarto del siglo XIX, por su mala conservaciâ”œâ”‚n, el templo se queda sin culto y en estado de ruina, por lo que se demuele. Previamente el patrimonio artâ”œÂ¡stico que poseâ”œÂ¡a se distribuye entre diversos templos de la archidiâ”œâ”‚cesis. Se conservan escasas piezas, en su mayor parte en el Museo Provincial y en el Palacio arzobispal de Zaragoza: capiteles, basas y trozos de fuste. El dibujo evidencia una imagen poco conocida de una parte de la iglesia. El templo, segâ”œâ•‘n podemos ver, se cubrâ”œÂ¡a con bâ”œâ”‚veda de crucerâ”œÂ¡a, parece ser que tuvo una sola nave y capillas laterales. Se puede advertir en la imagen un acceso por el lado del evangelio." En el dibujo, el acceso por la calle de Don Jaime queda a la derecha. Al fondo, los pies de la iglesia, con el coro y ventanal a la calle de Santiago. Foto: Archivo Ayuntamiento Zaragoza.', 1874, 1874, 1874, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65469900, -0.87726000, '0101000020E6100000C3D842908312ECBFA9DC442DCDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14959699729.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14959699729.webp', 'https://www.flickr.com/photos/zaragozaantigua/14959699729/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25651, 'Plaza Santa Cruz aâ”œâ–’os 20', 'Preside la remozada en formas neoclâ”œÃ­sicas Casa de los Tarâ”œÂ¡n, luego "del Canal Imperial". A la derecha, torre de la iglesia de Santa Cruz. La plaza es el resultado del piqueteo del antiguo palacio de los Francos de Villalba, que estaba justo enfrente de la casa de los Tarâ”œÂ¡n. Fuente: Archivo Ayuntamiento de Zaragoza.', 1920, 1920, 1929, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65418300, -0.87866300, '0101000020E6100000649126DE011EECBFB24CBF44BCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14988320402.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14988320402.webp', 'https://www.flickr.com/photos/zaragozaantigua/14988320402/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25653, 'Plaza de Santa Cruz 1966', 'Plaza de Santa Cruz, con la Casa del Canal a la izquierda y la iglesia de Santa Cruz al fondo. En primer plano, la cruz referida, otro mojâ”œâ”‚n en la ciudad de la memoria histâ”œâ”‚rica, que reza la leyenda "Transeâ”œâ•‘nte, esta cruz bendita espera de ti una oraciâ”œâ”‚n por los mâ”œÃ­rtires de la guerra R.I.P." Fuente visual: Gerardo Sancho Ramo, AMZ. 24/12/1966.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65422200, -0.87871700, '0101000020E6100000300E2E1D731EECBF6F29E78BBDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15211496825.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15211496825.webp', 'https://www.flickr.com/photos/zaragozaantigua/15211496825/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25657, 'Calle Espoz y Mina 1969', 'Imagen de la calle Espoz y Mina capturada desde el arranque de la calle Mayor, en el punto en que tal vez el decumano mâ”œÃ­ximo romano, del que estas dos calles serâ”œÂ¡an herederas, se cruzase con el cardo, que vendrâ”œÂ¡a a ser la calle Don Jaime I, de derecha a izquierda. En la esquina donde la seâ”œâ–’al de prohibido el paso, se alza el edificio diseâ”œâ–’ado por Francisco Albiâ”œâ–’ana, que hace estratâ”œÂ®gico chaflâ”œÃ­n. Un poco mâ”œÃ­s adelante, sobresale el alero volado del antiguo palacio renacentista de los Pardo, propiedad de la familia Moliner, y empleado como almacâ”œÂ®n de muebles. Unos pocos aâ”œâ–’os despuâ”œÂ®s serâ”œÂ¡a adquirido por una entidad local de ahorro, que lo convertirâ”œÃ­ en museo. Justo enfrente queda la iglesia de la Exaltaciâ”œâ”‚n de la Santa Cruz, pero como es tan modesta, ni se ve. A partir de ahâ”œÂ¡, la calle parece combarse hacia abajo hacia su cruce con la calle Alfonso I, y su continuaciâ”œâ”‚n natural, luego, por Manifestaciâ”œâ”‚n. Cosas de la perspectiva. Fuente: "Zaragoza viva" (1969)', 1969, 1969, 1969, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65425200, -0.87761800, '0101000020E610000090300C587215ECBFDAAB8F87BED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15676035218.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15676035218.webp', 'https://www.flickr.com/photos/zaragozaantigua/15676035218/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25663, 'Iglesia Santa Cruz 2006', 'Foto: Rusolera, abril de 2006. Aspecto de las traseras de la Iglesia de la Exaltaciâ”œâ”‚n de la Santa Cruz de Zaragoza (construida en 1768), con el solar resultante tras el derribo de sus construcciones anexas (restos del palacio de Osera). En 2014, tras medio siglo en ese estado, serâ”œÃ­ terminada una residencia del Opus Dei en su ubicaciâ”œâ”‚n. Fuente: zaragozaciudad.net/zaragozafluye/2014/110901-plaza-de-san...', 2006, 2006, 2006, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65445900, -0.87861700, '0101000020E61000004EB51666A11DECBF54C90050C5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21494849739.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21494849739.webp', 'https://www.flickr.com/photos/zaragozaantigua/21494849739/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25668, 'Calle Don Jaime I c.1920', 'Despejada visual de la calle de Don Jaime I, en direcciâ”œâ”‚n hacia la Lonja, que queda al fondo. A la izquierda, soleado desemboque de la calle de Espoz y Mina, con el reciente edificio chaflanero diseâ”œâ–’ado por Francisco Albiâ”œâ–’ana, de inspiraciâ”œâ”‚n moderna, y aires vieneses. Hacia la derecha, umbrâ”œÂ¡o arranque de la calle Mayor hacia la Magdalena. En el suelo, el tendido viario por el que transitaban las lâ”œÂ¡neas de tranvâ”œÂ¡a "Arrabal" y "Gâ”œÃ­llego". Fuente: Foto Jesâ”œâ•‘s Cormâ”œÃ­n Simâ”œâ”‚n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65404300, -0.87779100, '0101000020E6100000EE23B726DD16ECBFC09657AEB7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24810400281.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24810400281.webp', 'https://www.flickr.com/photos/zaragozaantigua/24810400281/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25678, 'Plaza de Santa Cruz 1922', 'Dibujo de â”œÃ¼ngel Dâ”œÂ¡az Domâ”œÂ¡nguez que reproduce la gran fachada de la casa del siglo XVI que fue de los Tarâ”œÂ¡n, del conde de Fuentes, del hospital de Gracia, del Santo Oficio y del Canal Imperial de Aragâ”œâ”‚n. Esta perspectiva es posible por el derribo de la gran casa de los Francos de Villalba, cuyo solar (en primer plano) dio origen a la plaza de Santa Cruz. A la derecha, brazo edilicio de la gran casa de los marqueses de Osera, sobre el que emerge la torrecilla de la iglesia parroquial de Santa Cruz. Fuente visual: Revista La Cadiera.', 1922, 1922, 1922, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65439900, -0.87881900, '0101000020E6100000404F0306491FECBF7EC4AF58C3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43150964012.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43150964012.webp', 'https://www.flickr.com/photos/zaragozaantigua/43150964012/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20886, 'Câ”œÂ®sar Augusto c.1954', 'Estatua de Câ”œÂ®sar Augusto donada por Mussolini a Zaragoza, originalmente emplazada en 1940 en la plaza de Paraâ”œÂ¡so, y desde 1950 reubicada junto a la muralla de piedra inmediata al torreâ”œâ”‚n de la Zuda y la iglesia de San Juan de los Panetes. Aâ”œâ–’os despuâ”œÂ®s volverâ”œÂ¡a a ser objeto de otros traslados. Fuente: AHPZ-Archivo Fotogrâ”œÃ­fico Josâ”œÂ® Galiay, (SF).', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65698400, -0.88184500, '0101000020E61000000E8464011338ECBF65FF3C0D18D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14700988999.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14700988999.webp', 'https://www.flickr.com/photos/zaragozaantigua/14700988999/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20897, 'Calle Manifestaciâ”œâ”‚n 2001', 'Las obras de renovaciâ”œâ”‚n de servicios a la altura del nâ”œâ•‘mero 4 de la calle de la Manifestaciâ”œâ”‚n pusieron al descubierto un tramo significativo de losas de la calzada romana del Decumano Mâ”œÃ­ximo. Bajo â”œÂ®ste, apareciâ”œâ”‚ tambiâ”œÂ®n una cloaca romana. Al fondo, confluencia con la calle Murallas Romanas. Fuente: Las cloacas de Cesaraugusta, IFC, 2013.', 2001, 2001, 2001, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65660000, -0.88201800, '0101000020E61000006C770FD07D39ECBFDC4603780BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23908883029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23908883029.webp', 'https://www.flickr.com/photos/zaragozaantigua/23908883029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20899, 'Torreâ”œâ”‚n muralla romana 1989', 'En el actual emplazamiento de la estatua de Augusto, junto al Mercado Central, se hallâ”œâ”‚ este basamento de un gran cubo semicircular de mâ”œÃ­s de 13 metros de diâ”œÃ­metro, de la muralla romana (siglo I). Corresponde al torreâ”œâ”‚n norte de la puerta Decumana Oeste, luego puerta de Toledo. Al fondo, iglesia de San Juan de los Panetes y solares en la calle de las Murallas Romanas. Fuera de campo y a la derecha, calle de la Manifestaciâ”œâ”‚n, antiguo Decumano Mâ”œÃ­ximo. Fuente: Zaragoza. Prehistoria y arqueologâ”œÂ¡a, Ayuntamiento de Zaragoza, 1991.', 1989, 1989, 1989, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65674400, -0.88225400, '0101000020E6100000637C98BD6C3BECBF10ECF82F10D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24297061796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24297061796.webp', 'https://www.flickr.com/photos/zaragozaantigua/24297061796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20907, 'Antonio Pâ”œÂ®rez 1591', '"El pueblo de Zaragoza poniendo en libertad a Antonio Pâ”œÂ®rez", D. Melâ”œÂ®ndez, 1878. Xilografâ”œÂ¡a. Antonio Pâ”œÂ®rez, diplomâ”œÃ­tico fugitivo de la Justicia de Felipe I, se acoge al Privilegio de Manifestaciâ”œâ”‚n en Aragâ”œâ”‚n, siendo custodiado en la Câ”œÃ­rcel Foral o de Manifestados de Zaragoza, en el torreâ”œâ”‚n sur del Arco de Toledo, en 1591. Por ello, parece que esta imagen reproduce la actual calle Manifestaciâ”œâ”‚n. Fuente: "La Academia", 23 de diciembre de 1878.', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65656600, -0.88209800, '0101000020E610000088BEBB95253AECBF30D5CC5A0AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15061489001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15061489001.webp', 'https://www.flickr.com/photos/zaragozaantigua/15061489001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20915, 'Antonio Pâ”œÂ®rez 1591', '"Antonio Pâ”œÂ®rez liberado por el pueblo aragonâ”œÂ®s en 1591", â”œâ”‚leo de Manuel Ferrâ”œÃ­n, 1860. El diplomâ”œÃ­tico Antonio Pâ”œÂ®rez es liberado, en el marco de las llamadas "Alteraciones de Aragâ”œâ”‚n". Su prisiâ”œâ”‚n era la de los manifestados, en el torreâ”œâ”‚n sur del Arco de Toledo de Zaragoza.', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65661600, -0.88220000, '0101000020E610000097FF907EFB3AECBFE2033BFE0BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19061099701.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19061099701.webp', 'https://www.flickr.com/photos/zaragozaantigua/19061099701/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20920, 'Calle Puerta de Toledo 1769', 'Plano de la calle Puerta de Toledo de Zaragoza, 1769. "Demarcaciâ”œâ”‚n de las casas que se hallan por una u otra ladera desde la casa que pretende abrir votiga Joseph Dieste, colejial cerero y confitero, Plaza del Mercado, asta la de Diego Casanoba, colejial, cerero y confitero, frente a San Antâ”œâ”‚n. Firmado por Onofre Graciâ”œÃ­n, maestro de obras." Fuente: AHPZ.', 1769, 1769, 1769, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65661600, -0.88220000, '0101000020E610000097FF907EFB3AECBFE2033BFE0BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20002419886.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20002419886.webp', 'https://www.flickr.com/photos/zaragozaantigua/20002419886/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21001, 'Puerta de Toledo c.1853', 'Dibujo de la antigua Puerta de Toledo (derribada finalmente en 1866) en una escena donde se muestra desde la plaza del Mercado, donde confluâ”œÂ¡an las calles de la Hilarza y de los Predicadores. El edificio de la izquierda formâ”œâ”‚ parte de las antiguas carnicerâ”œÂ¡as de la ciudad, y tras â”œÂ®l se ubicaba la antigua câ”œÃ­rcel o prisiâ”œâ”‚n de los Manifestados y la iglesia de San Antâ”œâ”‚n. Hacia el fondo, la calle del Arco de Toledo conducente a la subida de las Cucharas (antigua de Botoneros) y la plaza del Justicia, desde donde continuaba como calle de la Platerâ”œÂ¡a. A la derecha y adosadas a la puerta, bodeguillas o tiendas comerciales. Este dibujo fue mâ”œÃ­s tarde convertido despuâ”œÂ®s en xilografâ”œÂ¡a y publicado en el "Semanario Pintoresco Espaâ”œâ–’ol" (1853).', 1853, 1853, 1853, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65677700, -0.88231800, '0101000020E6100000138255F5F23BECBFEBE1CB4411D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52218508522.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52218508522.webp', 'https://www.flickr.com/photos/zaragozaantigua/52218508522/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21002, 'Puerta de Toledo y plaza del Mercado 1867', 'A.M.Z. Sign. 0907. "La plaza del Mercado", dibujo de Enrique Laporta basado en el de Valentâ”œÂ¡n Carderera de 1840, publicado en la revista El Museo Universal (17/02/1867). Esta puerta tuvo larga vida, desde la â”œÂ®poca romana (sus dos torreones corresponden a la muralla del s. IV) hasta 1848. Cerraba la ciudad hacia el este. La plaza representada estâ”œÃ­ ocupada por el actual Mercado Central, y la calle que cerraba la puerta hoy es Manifestaciâ”œâ”‚n.', 1867, 1867, 1867, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65653400, -0.88215000, '0101000020E6100000265305A3923AECBF255B5D4E09D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14672230150.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14672230150.webp', 'https://www.flickr.com/photos/zaragozaantigua/14672230150/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21073, 'Plaza del Mercado 1877', '"La procesiâ”œâ”‚n de la Virgen del Pilar en Zaragoza", litografâ”œÂ¡a de Mariano Teruel, 1877. Vista de la plaza del Mercado de Zaragoza, con el Torreâ”œâ”‚n de la Zuda al fondo. Fuente: "La Academia", semanario ilustrado universal, 23 de noviembre de 1877.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65635100, -0.88276900, '0101000020E610000023861DC6A43FECBF34D93F4F03D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20023326392.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20023326392.webp', 'https://www.flickr.com/photos/zaragozaantigua/20023326392/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21086, 'Procesiâ”œâ”‚n del Rosario 1871', '"Zaragoza. Procesiâ”œâ”‚n del Rosario en las Fiestas del Pilar". Dibujo de Francisco Pradilla publicado en el Almanaque de la Ilustraciâ”œâ”‚n para 1877, editado en 1876 por Aribau y Câ”¬Â¬, Madrid, procedente del nâ”œâ•‘mero del 30 de octubre de 1871 de la revista La Ilustraciâ”œâ”‚n, de Madrid. La procesiâ”œâ”‚n del Rosario desfila por la plaza del Mercado. Guâ”œÂ¡alos numerosa clerecâ”œÂ¡a y una exigua capilla musical, que entona la Letanâ”œÂ¡a lauretana. Grandes farolas de extraâ”œâ–’as formas, ya representando macetas y leones, ya templetes y aun castillos, conforman el inmemorial Rosario de la imagen. En â”œÂ®l no figura aâ”œâ•‘n el gran farol del Templo del Pilar, que se situaba detrâ”œÃ­s de los leones y que se estrenâ”œâ”‚ en 1872. Es el precedente del actual Rosario de Cristal, cuyos pasos y faroles fueron diseâ”œâ–’ados por Ricardo Magdalena Tabuenca en 1889 y 1890 y realizados por el vidriero Leâ”œâ”‚n Quintana Bianchi. Fuente visual: prensahistorica.mcu.es/es/catalogo_imagenes/grupo.do?path...', 1871, 1871, 1871, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65662200, -0.88260900, '0101000020E6100000ECF7C43A553EECBFC4EA8F300CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30966735445.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30966735445.webp', 'https://www.flickr.com/photos/zaragozaantigua/30966735445/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21151, 'Mercado de Zaragoza 1893', '"Zaragoza", acuarela de Arthur Melville, 1893. Vista interior de los porches del Mercado de Zaragoza. No confundir con el â”œâ”‚leo "The Orange Market" del mismo autor, que ha sido relacionado con la ciudad de Zaragoza y es una estampa del Puerto de Pasajes (Guipâ”œâ•‘zcoa).', 1893, 1893, 1893, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65607900, -0.88276900, '0101000020E610000023861DC6A43FECBFD34B8C65FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18456936174.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18456936174.webp', 'https://www.flickr.com/photos/zaragozaantigua/18456936174/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21288, 'Calle Manifestaciâ”œâ”‚n c.1908', '"Zaragoza. Plaza del Mercado." Sobresaliente imagen editada como postal en Hamburgo, por la editorial V. B. Cumbo, con una insâ”œâ”‚lito panorama del ajetreo propio del entorno del Mercado Nuevo, en su entrada norte. La imagen se ha capturado desde la calle de la Manifestaciâ”œâ”‚n. A la derecha, inmediatas, viviendas esquineras entre esa calle y la plaza de San Antonio Abad, que queda justo fuera de plano. Las traseras de estas viviendas estaban adosadas al antiguo gran complejo hospitalario de San Juan de los Panetes. Al fondo, los porches de la plaza del Mercado. y el tramo final de la calle de la Democracia, esquinero con la calle de Antonio Pâ”œÂ®rez. Mâ”œÃ­s al fondo, leve emboque al â”œÂ¡nfimo callejâ”œâ”‚n del Arpa. Fuente visual: www.todocoleccion.net/', 1908, 1908, 1908, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65674400, -0.88225400, '0101000020E6100000637C98BD6C3BECBF10ECF82F10D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26291005183.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26291005183.webp', 'https://www.flickr.com/photos/zaragozaantigua/26291005183/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21405, 'Iglesia de San Cayetano c.1915', 'Fachada de la iglesia de San Cayetano o Santa Isabel, en la plaza de San Cayetano, hoy del Justicia. Fuente: www.ebay.com/', 1915, 1915, 1915, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65595000, -0.88190000, '0101000020E6100000F1F44A598638ECBFD5E76A2BF6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25477525352.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25477525352.webp', 'https://www.flickr.com/photos/zaragozaantigua/25477525352/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21450, 'Plaza de Lanuza c.1915', 'Imagen capturada en la plaza de Lanuza, a cierta altura y desde un inmueble de la manzana entre las calles de las Armas y de Casta â”œÃ¼lvarez, con el nuevo Mercado inmediato y a la derecha, y con el fondo de la calle de Antonio Pâ”œÂ®rez, donde se destaca emergente y levemente, entre edificaciones adosadas, el Torreâ”œâ”‚n de la Zuda. En la pronunciada esquina de esta calle con el arranque de la calle de la Democracia destaca el antiguo Cafâ”œÂ® Espaâ”œâ–’ol (no confundir con el mâ”œÃ­s antiguo y homâ”œâ”‚nimo cafâ”œÂ® de la plaza de la Constituciâ”œâ”‚n). Sobre el firme, tendido tranviario de la lâ”œÂ¡nea de Circunvalaciâ”œâ”‚n.', 1915, 1915, 1915, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65665700, -0.88281100, '0101000020E6100000DE91B1DAFC3FECBF41D829560DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50746748743.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50746748743.webp', 'https://www.flickr.com/photos/zaragozaantigua/50746748743/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21505, 'Plaza del Pilar 1925', 'Miguel Faci Abad. 1920-1925. "Zaragoza. Plaza del Pilar". A las 12 de la maâ”œâ–’ana de un soleado dâ”œÂ¡a primaveral, los juegos de luces y sombras de la antigua plaza del Pilar festejaban los contrastes, difuminaban los espacios. La plaza lucâ”œÂ¡a un microclima propio, irrepetible despuâ”œÂ®s. Era otra plaza. La imagen estâ”œÃ­ capturada desde la esquina con la calle de la Regla (que conectaba con la trasera plaza de Huesca), justo al lado del edificio que servâ”œÂ¡a de vivienda y consulta al Doctor Palomar. A su izquierda, visible en la imagen, el edificio que albergâ”œâ”‚ al palacio de Aytona, y que luego serâ”œÃ­ sede de la Delegaciâ”œâ”‚n de Hacienda. Entre â”œÂ®l y el Pilar, la callecita Retiro Alto del Pilar. El ciudadano cubierto con canotier, dirigido en direcciâ”œâ”‚n hacia la calle Convertidos. Fuente visual: "Miguel y Gabriel Faci. Fotâ”œâ”‚grafos fundadores de la Real Sociedad Fotogrâ”œÃ­fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaciâ”œâ”‚n Provincial de Zaragoza, 1999.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65684100, -0.88027900, '0101000020E6100000F2608BDD3E2BECBF02D6AA5D13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15583628299.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15583628299.webp', 'https://www.flickr.com/photos/zaragozaantigua/15583628299/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21603, 'Plaza de Huesca 1929', '"A Zaragoza", dibujo de Fâ”œÂ®lix Gazo para la portada del Heraldo de Aragâ”œâ”‚n del 12 de octubre de 1929. Representa una escena con viajeros del coche de lâ”œÂ¡nea en la plaza de Huesca, con la iglesia de San Juan de los Panetes al fondo. Fuente: www.heraldo.es', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65708700, -0.88064600, '0101000020E61000008C4D2B85402EECBF39D0436D1BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26477374166.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26477374166.webp', 'https://www.flickr.com/photos/zaragozaantigua/26477374166/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21713, 'San Juan de los Panetes c.1934', 'Vista dibujada desde el Torreâ”œâ”‚n de la Zuda de la iglesia de San Juan de los panetes de Zaragoza. Fuente: Keecua.com', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65703200, -0.88167600, '0101000020E61000000B613596B036ECBF7636E49F19D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18817190394.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18817190394.webp', 'https://www.flickr.com/photos/zaragozaantigua/18817190394/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21725, 'Pl. del Justicia 1930', 'Foto: A. de la Barrera, 1930. Imagen de la plaza del Justicia con la antigua casa de los condes de Sobradiel al fondo. Ese mismo aâ”œâ–’o serâ”œÂ¡a inaugurado el edificio como Ilustre Colegio Notarial de Aragâ”œâ”‚n. Fuente: La Voz de Aragâ”œâ”‚n, 3 de abril de 1930.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65614300, -0.88195400, '0101000020E6100000BD715298F738ECBFEA3F6B7EFCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20357497138.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20357497138.webp', 'https://www.flickr.com/photos/zaragozaantigua/20357497138/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21806, 'Pl. del Justicia 1934', 'Fachada del almacâ”œÂ®n de plâ”œÃ­tanos de Pascual Castejâ”œâ”‚n, sito en la plaza del Justicia 4, esquina con la calle del Temple. Fuente: www.20minutos.es', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65592600, -0.88163200, '0101000020E6100000226DE34F5436ECBF4D4C1762F5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28458081882.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28458081882.webp', 'https://www.flickr.com/photos/zaragozaantigua/28458081882/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21861, 'Pl. de San Antâ”œâ”‚n 1933', 'Imagen capturada en la antigua y arbolada plaza de San Antonio Abad, o de San Antâ”œâ”‚n, abierto espacio resultante del derribo del que fuera convento-iglesia que la Orden Antoniana tuviera en esta ubicaciâ”œâ”‚n desde el siglo XII, y hasta su supresiâ”œâ”‚n por Bula Papal a finales del siglo XVIII. Los edificios de la imagen habâ”œÂ¡an sido construidos adosados a la antigua muralla de piedra de la ciudad, y sus traseras lindaban con las de los nâ”œâ•‘meros pares de la calle de Antonio Pâ”œÂ®rez, que tambiâ”œÂ®n descansaban sobre la argamasa y piedras del recinto amurallado pâ”œÂ®treo de la ciudad. Hacia la derecha se encontraba el acceso que desde la plaza de San Antâ”œâ”‚n conducâ”œÂ¡a al interior del antiguo complejo hospitalario de la Orden de San Juan de Jerusalâ”œÂ®n, al que estaban incorporados el torreâ”œâ”‚n de la Zuda y la iglesia de San Juan de los Panetes. Los edificios de la imagen mâ”œÃ­s tarde fueron derribados y la zona reordenada urbanisticamente, de forma que la plaza devino en frâ”œÂ¡a calleja de limitado eco ciudadano y nula indicaciâ”œâ”‚n informativa. En no siendo asuntos referidos a mitos medievales, ni hazaâ”œâ–’as bâ”œÂ®licas, silencio, no hay banda. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65660000, -0.88201800, '0101000020E61000006C770FD07D39ECBFDC4603780BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36289551531.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36289551531.webp', 'https://www.flickr.com/photos/zaragozaantigua/36289551531/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21941, 'El Pilar aâ”œâ–’os 40', 'El Pilar, aguafuerte, Jesâ”œâ•‘s Fernâ”œÃ­ndez Barrio, Diputaciâ”œâ”‚n de Zaragoza, c. 1945-1947. Fuente: web.dpz.es/arscatalogi.es/', 1940, 1940, 1949, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65708700, -0.88064600, '0101000020E61000008C4D2B85402EECBF39D0436D1BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15689319950.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15689319950.webp', 'https://www.flickr.com/photos/zaragozaantigua/15689319950/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21966, 'Plaza del Pilar 1949', 'Imagen de la plaza del Pilar desde la leve altura del "Monumento a los Hâ”œÂ®roes y Mâ”œÃ­rtires de Nuestra Gloriosa Cruzada", en obras desde 1946. Uno de los maderos del andamiaje, a la derecha, causa un perturbador efecto â”œâ”‚ptico sobre una plaza terrosa y vacâ”œÂ¡a, en construcciâ”œâ”‚n y remodelaciâ”œâ”‚n. A la izquierda, por ejemplo, donde estuviera el antiguo palacio de los Urriâ”œÂ®s y el anexo colegio de San Nicolâ”œÃ­s Tolentino, un perâ”œÂ¡metro vallado seâ”œâ–’ala el proyecto de Regino Borobio para el nuevo edificio del Colegio de Infantes, Museo Catedralicio, y viviendas para capellanes y capitulares del Pilar. Al lado, y desde 1945, estaban en pie los andamios de obra de la nueva y monumental fachada sur del Pilar, proyectada por Teodoro Râ”œÂ¡os, y con 8 nuevos bultos redondos de Antonio Torres (7), y Fâ”œÂ®lix Burriel (1). Los â”œÃ­rboles del centro recuerdan el espacio de la antigua y barroca plaza del Pilar, antes de ser cortados para unificar visualmente la nueva y mayâ”œâ•‘scula plaza, concebida por el Râ”œÂ®gimen franquista como el centro espiritual e imperial de la ciudad. Fuente Visual: Fotos Ysa, Archivo Pâ”œâ•‘blico Municipal.', 1949, 1949, 1949, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65683300, -0.87974300, '0101000020E61000005551BCCADA26ECBF7FF78E1A13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22196717455.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22196717455.webp', 'https://www.flickr.com/photos/zaragozaantigua/22196717455/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22013, 'Plaza del Pilar 1946', 'Familiar e inâ”œÂ®dita imagen capturada en la plaza del Pilar con el fondo de la calle de Florencio Jardiel flanqueada por el templo del Pilar a la derecha, y por el solar adjudicado a la izquierda para la construcciâ”œâ”‚n de la Casa del Cabildo, el Museo Catedralicio y el nuevo Colegio de los Infantes. Las efâ”œÂ¡meras construcciones del fondo se corresponden con los talleres y naves habilitados para el modelado y talla de las esculturas instaladas en la fachada meridional del templo durante las obras de rehabilitaciâ”œâ”‚n del templo acometidas en la segunda mitad de los aâ”œâ–’os cuarenta y primeros aâ”œâ–’os cincuenta. Estas obras fueron resultado del trabajo de escultores como Antonio Torres Clavero y Fâ”œÂ®lix Burriel, con el respaldo de Jacinto Suâ”œÃ­rez y los canteros Josâ”œÂ® Muâ”œâ–’oz, Manuel Macia y Basilio Sorolla. En primer tâ”œÂ®rmino, un joven zaragozano de nombre Jaime Grima Casanova juega con su carretillo de juguete en una zona en construcciâ”œâ”‚n desde los derribos por ampliaciâ”œâ”‚n de la antigua plaza del Pilar. Le acompaâ”œâ–’a, vigilante, su abuelo.', 1946, 1946, 1946, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65691400, -0.87965700, '0101000020E6100000B151D66F2626ECBF6C2409C215D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47671814631.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47671814631.webp', 'https://www.flickr.com/photos/zaragozaantigua/47671814631/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22029, 'Calle Imperial 1944', 'Imagen tomada en la antigua calle de Antonio Pâ”œÂ®rez con el estado de la misma una vez que se han derribado y retirado los escombros de las decimonâ”œâ”‚nicas viviendas que estaban adosadas al tramo de las antiguas murallas de piedra junto al Torreâ”œâ”‚n de la Zuda, que ademâ”œÃ­s aparece con los andamios de obra durante la intervenciâ”œâ”‚n que supuso su restauraciâ”œâ”‚n/reinvenciâ”œâ”‚n. Centran la escena dos de los cubos de la muralla despejados de las casas que los ocultaban. Al fondo y a la izquierda, cableado de la pasarela de Macanaz. En paralelo a esta actuaciâ”œâ”‚n se procediâ”œâ”‚ a la sustituciâ”œâ”‚n, signo de aquellos tiempos, de la calle de Antonio Pâ”œÂ®rez por la calle Imperial. Tras la muralla queda la plaza de Câ”œÂ®sar Augusto y la iglesia de San Juan de los Panetes.', 1944, 1944, 1944, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65710600, -0.88225300, '0101000020E61000004C88B9A46A3BECBFB000A60C1CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50811432422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50811432422.webp', 'https://www.flickr.com/photos/zaragozaantigua/50811432422/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22041, 'Plaza del Justicia 1951', 'La plaza del Justicia, un recoleto espacio abierto junto a la calle de la Manifestaciâ”œâ”‚n, en una imagen con su isleta central de jardines, â”œÃ­rboles y bancos que la caracterizaba desde unas dâ”œÂ®cadas antes. A la derecha, la antigua casa de los Sobradiel y de los Gabarda, hasta que en los aâ”œâ–’os 30 fue habilitada como sede del Ilustre Colegio Notarial de Aragâ”œâ”‚n. Al fondo, la fachada barroca de la iglesia de Santa Isabel o de San Cayetano, denominaciâ”œâ”‚n popular esta â”œâ•‘ltima que tambiâ”œÂ®n es comâ”œâ•‘n para identificar este espacio. En 1962 fue instalada aquâ”œÂ¡ la fuente de La Samaritana, procedente de la plaza de La Seo.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65602400, -0.88153600, '0101000020E61000009BE447FC8A35ECBF10B22C98F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14741052938.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14741052938.webp', 'https://www.flickr.com/photos/zaragozaantigua/14741052938/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22180, 'Pl. de Lanuza 1954', 'Hospederâ”œÂ¡a Carroll y San Jorge situada en la plaza de Lanuza nâ”¬â•‘ 27, en la manzana de edificios adosados a la antigua muralla de piedra y frente a la puerta norte del Mercado Central. Un recordatorio de las numerosas posadas y mesones que estuvieron localizados en el entorno de la antigua plaza del Mercado. Aâ”œâ–’os despuâ”œÂ®s, esta manzana serâ”œÂ¡a derribada. Fuente visual: Revista Aragâ”œâ”‚n, abril, mayo y junio de 1954.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65673400, -0.88239500, '0101000020E6100000EAEC6470943CECBFEC1516DC0FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31797596720.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31797596720.webp', 'https://www.flickr.com/photos/zaragozaantigua/31797596720/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22264, 'Plaza del Justicia 1967', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 24/03/1967. Extraordinaria y aguerrida columna de recios y pavorosos legionarios romanos, pasando por el trance de la figuraciâ”œâ”‚n durante la conmemoraciâ”œâ”‚n anual cristiana de la Pasiâ”œâ”‚n, Muerte y Resurrecciâ”œâ”‚n del nazareno Jesâ”œâ•‘s. La imagen recoge el ardoroso despliegue guerrero en la Plaza del Justicia. Al fondo, la iglesia de Santa Isabel, o San Cayetano. Esta "Guardia Pretoriana" estaba formada por un centuriâ”œâ”‚n y varios soldados, ademâ”œÃ­s de tambor y clarâ”œÂ¡n, y acompaâ”œâ–’aba al paso de "Jesâ”œâ•‘s camino del Calvario" ("Jesus walked to Calvary").', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65622400, -0.88159900, '0101000020E610000034F6251B0F36ECBFD76CE525FFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14825797250.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14825797250.webp', 'https://www.flickr.com/photos/zaragozaantigua/14825797250/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22280, 'Murallas Romanas 1966', 'Ayuntamiento de Zaragoza/Gerardo Sancho, 2/2/66. Basamento y columnas del Augusto de Prima Porta, exhibido junto al torreâ”œâ”‚n de la Zuda (derecha) entre 1950 y 1966 y retirado antes de hacer la foto. Antes y despuâ”œÂ®s estuvo en distintas ubicaciones de la ciudad; hoy se puede ver muy cerca. En el pedestal se lee: "Aquâ”œÂ¡ el aâ”œâ–’o XXIII a. de J.C. las legiones IIII Macedâ”œâ”‚nica, VI Victrix y X Gâ”œÂ®mina fundaron la Colonia Caesaraugusta". Mâ”œÃ­s informaciâ”œâ”‚n: jorge-entrecomillas.blogspot.com.es/2012/05/la-estatua-de...', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65701000, -0.88182200, '0101000020E610000003965CC5E237ECBF8E9257E718D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15003904019.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15003904019.webp', 'https://www.flickr.com/photos/zaragozaantigua/15003904019/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22361, 'Pl. de Lanuza c.1968', 'Foto: Jesâ”œâ•‘s Domeque. Aspecto del derribo de la manzana de casas que perduraba en la actual ubicaciâ”œâ”‚n de la estatua de Câ”œÂ®sar Augusto, frente a la puerta norte del Mercado Central. Al fondo de la calle Murallas Romanas, iglesia de San Juan de los Panetes. Fuente: www.facebook.com/photo.php?fbid=10204804368382012&set...', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65674400, -0.88225400, '0101000020E6100000637C98BD6C3BECBF10ECF82F10D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21035754534.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21035754534.webp', 'https://www.flickr.com/photos/zaragozaantigua/21035754534/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22428, 'Calle de las Murallas 1965', 'Colorista imagen capturada en la calle de las Murallas, entre la calle de la Manifestaciâ”œâ”‚n y la plaza de Câ”œÂ®sar Augusto, centrada en un tramo de las antiguas murallas de piedra de la ciudad y el torreâ”œâ”‚n de la Zuda. A la derecha, vista parcial de la iglesia de San Juan de los Panetes. Fuente visual: Lala Aufsberg, Bildarchiv Foto Marburg.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65707100, -0.88185800, '0101000020E610000036E9B6442E38ECBF34130CE71AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27988842839.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27988842839.webp', 'https://www.flickr.com/photos/zaragozaantigua/27988842839/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22463, 'Mercado Central 1968', 'Desfile de la Hermandad Provincial de Caballeros Legionarios de Zaragoza que, desde la calle de Manifestaciâ”œâ”‚n (al fondo), estâ”œÃ­ llegando a paso ligero a la altura del Mercado Central, flanqueada por nutrida parroquia que contiene el aliento ante esta necrofâ”œÂ¡lica demostraciâ”œâ”‚n. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65673400, -0.88239500, '0101000020E6100000EAEC6470943CECBFEC1516DC0FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32587924561.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32587924561.webp', 'https://www.flickr.com/photos/zaragozaantigua/32587924561/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22466, 'Pl. del Justicia 1967', 'Imagen de las traseras del simplificado "Paso de la Caâ”œÂ¡da del Seâ”œâ–’or", conducido por la "Cofradâ”œÂ¡a de Jesâ”œâ•‘s Camino del Calvario", durante la nocturna Procesiâ”œâ”‚n de las Tres Caâ”œÂ¡das. Acompaâ”œâ–’ando al paso, tremendista procesionaria de descalzos penitentes cargando madero y arrastrando cadenas, y penitentas expiando culpas. La captura se ha realizado en la plaza del Justicia, con el fondo edilicio de la calle Manifestaciâ”œâ”‚n. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65619700, -0.88135400, '0101000020E6100000705CC64D0D34ECBFDD5D6743FED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32902408685.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32902408685.webp', 'https://www.flickr.com/photos/zaragozaantigua/32902408685/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22555, 'Vista parcial 1970', 'Desde el excelente mirador de la torre de San Francisco de Borja del Pilar, con el marco de uno de sus vanos, y en una tarde de frâ”œÂ¡o y niebla, vista orientada al oeste. Al fondo, la torre de San Pablo. A la izquierda, las dos torres de la iglesia de Santa Isabel y el Mercado Central. Mâ”œÃ­s inmediata, la plaza del Pilar, con el Altar de la Patria. Despuâ”œÂ®s, la plaza de Câ”œÂ®sar Augusto, las murallas romanas y la iglesia de San Juan de los Panetes.', 1970, 1970, 1970, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65696300, -0.88034100, '0101000020E6100000747E8AE3C02BECBF4DD7135D17D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15065655424.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15065655424.webp', 'https://www.flickr.com/photos/zaragozaantigua/15065655424/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22566, 'Mercado Central 1973', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Octubre 1973. Otro de los comercios veteranos con aires mâ”œÃ­s de la antigua plaza del Mercado, que del Mercado Central. Sogas, cuerdas, cestas, derivados textiles naturales cuando el boom del momento era el plâ”œÃ­stico, el polyester, el papel pintado de diseâ”œâ–’os romboidales. La imagen estâ”œÃ­ tomada en el pedacito de Câ”œÂ®sar Augusto entre Casta â”œÃ¼lvarez (hacia la derecha) y Predicadores (a la espalda). El Mercado Central queda, fuera de plano, inmediato a la izquierda.', 1973, 1973, 1973, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65670500, -0.88264300, '0101000020E6100000F16261889C3EECBF520FD1E80ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15232287261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15232287261.webp', 'https://www.flickr.com/photos/zaragozaantigua/15232287261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22567, 'Mercado Central 1974', 'El Mercado Central no encajaba con el Plan Parcial de la Vâ”œÂ¡a Imperial de 1973. Al incluir su derribo, marcâ”œâ”‚ el inicio de la campaâ”œâ–’a Salvemos al mercado que recogiâ”œâ”‚ mâ”œÃ­s de 30.000 firmas y el apoyo de entidades y personalidades de la ciudad. En 1978, un Real Decreto declarâ”œâ”‚ monumento histâ”œâ”‚rico-artâ”œÂ¡stico de carâ”œÃ­cter nacional el edificio del mercado de Lanuza. En la imagen, chavalerâ”œÂ¡a dâ”œÃ­ndole a la pelota frente al ingreso norte del Mercado Lanuza.', 1974, 1974, 1974, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65684100, -0.88225300, '0101000020E61000004C88B9A46A3BECBF02D6AA5D13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15234006727.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15234006727.webp', 'https://www.flickr.com/photos/zaragozaantigua/15234006727/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
