INSERT INTO public.photos VALUES (22877, 'Vista desde iglesia Sta. Isabel 1987', 'Luis Mâ”œÂ¡nguez. 1987. Desde la torre de la iglesia de Santa Isabel de Portugal mâ”œÃ­s cercana a la calle del Buen Pastor, una mirada perspectiva hacia el Norte, que nos conduce a las Murallas Romanas, el Torreâ”œâ”‚n de la Zuda, el puente de Santiago, la avenida de los Pirineos, el parque del Tâ”œÂ¡o Jorge a la derecha, los bloques de vivienda de la margen izquierda, hasta los montes de Juslibol.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65593600, -0.88208100, '0101000020E61000000589EDEE013AECBF7022FAB5F5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15851644101.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15851644101.webp', 'https://www.flickr.com/photos/zaragozaantigua/15851644101/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22905, 'Av. Câ”œÂ®sar Augusto 1989', 'Porches junto al Mercado Central, en la avenida Câ”œÂ®sar Augusto, tramo comprendido entre las calles del Buen Pastor y del Olmo, el 14 de febrero de 1989. Las columnas forjadas en Averly son parte de un proyecto inacabado de Ricardo Magdalena, que pretendâ”œÂ¡a que rodeasen todo el mercado. Fuente: "Memoria de las calles de Zaragoza", Juliâ”œÃ­n Ruiz Marâ”œÂ¡n, Librerâ”œÂ¡a General, 1997.', 1989, 1989, 1989, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65607900, -0.88276900, '0101000020E610000023861DC6A43FECBFD34B8C65FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21784624740.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21784624740.webp', 'https://www.flickr.com/photos/zaragozaantigua/21784624740/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22931, 'Calle de Prudencio 1987', 'Imagen capturada desde cierta altura en las traseras de los Juzgados de la plaza del Pilar, con el panorama previo a la ampliaciâ”œâ”‚n realizada entre 1991 y 1993 con proyecto de Alejandro de la Sota Martâ”œÂ¡nez y Juan Capella Callis. El montaje fotogrâ”œÃ­fico de la â”œÂ®poca abarca desde la calle de los Convertidos, a la izquierda, pasando por la de Prudencio, al frente, y llega hasta la calle de la Virgen y de las Danzas, a la derecha. Tras la finalizaciâ”œâ”‚n del derribo de los nâ”œâ•‘meros impares de la antigua calle de las Danzas, el espacio resultante devino en otro gran aparcamiento en superficie que durâ”œâ”‚ hasta el inicio de las obras. Fuente visual: www.alejandrodelasota.org/', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65638700, -0.88028900, '0101000020E6100000D5E940D6532BECBF81423D7D04D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31271465793.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31271465793.webp', 'https://www.flickr.com/photos/zaragozaantigua/31271465793/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
