INSERT INTO public.photos VALUES (23048, 'Calle de los Predicadores 1991', 'Imagen capturada durante la oficial inauguraciâ”œâ”‚n de la calle de los Predicadores tras las obras de reforma integral, durante las cuales se renovaron los servicios y el pavimento de este vial. En esta calle tambiâ”œÂ®n, signo de los tiempos, se recuperâ”œâ”‚ para el firme carretero un moderno adoquinado de piedra que con el tiempo fue dando problemas de mantenimiento solventados con econâ”œâ”‚micos parches de asfalto. En la imagen, capturada en el arranque de la calle desde la avenida de Câ”œÂ®sar Augusto, ceremonia oficial de inauguraciâ”œâ”‚n de la reformada calle con el preceptivo corte de cinta por el alcalde Antonio Gonzâ”œÃ­lez Triviâ”œâ–’o, aquâ”œÂ¡ acompaâ”œâ–’ado por su "nâ”œâ•‘mero 2", el Primer Teniente de Alcalde y concejal de Urbanismo, Luis Garcâ”œÂ¡a Nieto. En segundo tâ”œÂ®rmino, el Mercado Central Lanuza.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65682500, -0.88265000, '0101000020E6100000910F7A36AB3EECBFFC1873D712D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50437637038.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50437637038.webp', 'https://www.flickr.com/photos/zaragozaantigua/50437637038/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23148, 'Plaza del Pilar 2009', 'Viâ”œâ–’eta de la historieta "La gran invasiâ”œâ”‚n", de Alfonso Pinedo, incluida en el volumen de câ”œâ”‚mic "Hotel Safari", editado en Zaragoza en 2009. Se puede observar una batalla en la que estâ”œÃ­n presentes un ejâ”œÂ®rcito de zombies nazis, guerreros ninja, robots mutantes soviâ”œÂ®ticos, gorilas gigantes, etc. Al fondo, la basâ”œÂ¡lica del Pilar, en el momento de perder la torre de San Francisco de Borja. Fuente: Heraldo de Aragâ”œâ”‚n.', 2009, 2009, 2009, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65684300, -0.88006900, '0101000020E61000004A26A7768629ECBFA3CD716E13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32165857534.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32165857534.webp', 'https://www.flickr.com/photos/zaragozaantigua/32165857534/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23187, 'Manuel Ureâ”œâ–’a 2010', 'Foto Primo Romero, 2010. Viernes Santo, 2 de abril de 2010. El arzobispo de Zaragoza, Manuel Ureâ”œâ–’a, que habâ”œÂ¡a sustituido en 2005 a Elâ”œÂ¡as Yanes, se asoma a un balcâ”œâ”‚n del Colegio de Notarios, en la plaza del Justicia de Zaragoza, durante los actos de la Semana Santa. A su lado, sin motivo aparente, el alcalde de la ciudad (2003-2015), Juan Alberto Belloch. Ureâ”œâ–’a fue cesado en noviembre de 2014 por encubrir abusos sexuales. Belloch habâ”œÂ¡a anunciado en septiembre que no se volverâ”œÂ¡a a presentar a las elecciones municipales de 2015. Fuente: www.mhuel.org/paginas/noticias.htm', 2010, 2010, 2010, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65606900, -0.88181700, '0101000020E610000091D10149D837ECBFB075A911FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15346156732.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15346156732.webp', 'https://www.flickr.com/photos/zaragozaantigua/15346156732/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23788, 'Nevada plaza del Pilar 1967', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/invierno 1967. Despuâ”œÂ®s de que la antigua plaza del Pilar se tragara a sus colindantes de la antigua plaza de La Seo, y de la antigua plaza de Huesca, los dâ”œÂ¡as de nieve y borrasca este era el mayor receptâ”œÃ­culo de cristales de hielo de toda la antigua ciudad romana. Y la chavalerâ”œÂ¡a lo sabâ”œÂ¡a. Nada que ver con esos lejanos dâ”œÂ¡as de ferragosto, con sol martilleante, delirante.', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65705800, -0.88048300, '0101000020E610000011E335AFEA2CECBF9FC9FE791AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14664877380.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14664877380.webp', 'https://www.flickr.com/photos/zaragozaantigua/14664877380/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23798, 'La Cruz y sus Caâ”œÂ¡dos 1954', 'Ayuntamiento de Zaragoza/Marâ”œÂ¡n Chivite. (SF). Un decreto del general Franco de 16/XI/1938 proclamaba dâ”œÂ¡a de luto nacional el 20 de noviembre de cada aâ”œâ–’o, en memoria de Josâ”œÂ® Antonio Primo de Rivera, y establecâ”œÂ¡a, "previo acuerdo con las autoridades eclesiâ”œÃ­sticas, que en los muros de cada parroquia figure una inscripciâ”œâ”‚n que contenga los nombres de sus Caâ”œÂ¡dos, ya en la presente Cruzada, ya vâ”œÂ¡ctimas de la revoluciâ”œâ”‚n marxista." Ese fue el origen de la colocaciâ”œâ”‚n de placas en las iglesias y de la construcciâ”œâ”‚n de monumentos conmemorativos "a los caâ”œÂ¡dos". Despuâ”œÂ®s de abril de 1939, Espaâ”œâ–’a se llenâ”œâ”‚ de memoria de los vencedores. En Zaragoza, 1941, el alcalde Francisco Caballero propuso eternizar el recuerdo "de nuestros mejores", y un aâ”œâ–’o despuâ”œÂ®s la Corporaciâ”œâ”‚n Municipal convocâ”œâ”‚ un concurso para realizar un monumento funerario. Tras varios proyectos inviables, el monumento, rematado por una gran cruz, se colocâ”œâ”‚ en la Plaza del Pilar en 1954, dedicado "A los hâ”œÂ®roes y mâ”œÃ­rtires de Zaragoza. Caâ”œÂ¡dos en la Cruzada de Liberaciâ”œâ”‚n 1936-1939." Allâ”œÂ¡, cada 20 de noviembre, hasta el final de la Dictadura, se celebraba un acto de homenaje en el que participaban las principales autoridades militares, religiosas, y civiles. En 1990, con motivo de la remodelaciâ”œâ”‚n de la Plaza del Pilar, la Gerencia de Urbanismo del Ayuntamiento de Zaragoza lo trasladâ”œâ”‚ al Cementerio de Torrero y puso, en su lugar, la actual "Fuente de la Hispanidad".', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65714600, -0.88078900, '0101000020E610000040A6B5696C2FECBF3E59315C1DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14915587645.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14915587645.webp', 'https://www.flickr.com/photos/zaragozaantigua/14915587645/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23841, 'Plaza del Pilar 1967', 'La gran innovaciâ”œâ”‚n en la designaciâ”œâ”‚n de "procuradores" para la IXâ”¬Â¬ Legislatura de las franquistas Cortes Espaâ”œâ–’olas, fue la posibilidad de presentar candidatos por el tercio de masculinos cabezas de familia, y elegir entre ellos, o abstenerse. En la pugna para los dos puestos de la provincia de Zaragoza se presentaron ocho aspirantes. Uno de ellos era Faustino Ferrer Lledâ”œâ”‚, natural de Fuentes de Ebro, antiguo alfâ”œÂ®rez provisional metido a exitoso empresario en "Abad Metales", que tras pasar por la presidencia del Real Zaragoza (1958-62), y la vicepresidencia de la DPZ, se postulâ”œâ”‚ a Cortes Generales. Con el perturbador lema "Pienso en vuestras familias porque pienso en la mâ”œÂ¡a", publicitâ”œâ”‚ su candidatura sin muchas posibilidades, porque los vencedores fueron los previstos: el ex-alcalde Luis Gâ”œâ”‚mez Laguna, y el radiofâ”œâ”‚nico "vigâ”œÂ¡a de la Torre Nueva", Josâ”œÂ® Marâ”œÂ¡a Zaldâ”œÂ¡var. A Faustino Ferrer le tocarâ”œÂ¡a ser procurador en la siguiente Xâ”¬Â¬ Legislatura, que se alargarâ”œÂ¡a hasta 1977 por cierto suceso imprevisto acaecido el 20-N de 1975. En la imagen, exposiciâ”œâ”‚n del Censo Electoral en la fachada del Convento de las Hijas de la Caridad de Santa Ana, en la plaza del Pilar, durante las elecciones de 1967 a procuradores por el tercio de las cabezas nucleares de familia. Fuente: Gerardo Sancho Ramo (Archivo Pâ”œâ•‘blico Municipal).', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65689100, -0.88080400, '0101000020E610000095F3C5DE8B2FECBFB404190115D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23679627739.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23679627739.webp', 'https://www.flickr.com/photos/zaragozaantigua/23679627739/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23842, 'Plaza del Pilar c.1941', 'Obras de remodelaciâ”œâ”‚n de la plaza del Pilar. Al fondo, la Zuda y San Juan de los Panetes. Fuente: Agencia EFE.', 1941, 1941, 1941, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65708700, -0.88064600, '0101000020E61000008C4D2B85402EECBF39D0436D1BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24243646029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24243646029.webp', 'https://www.flickr.com/photos/zaragozaantigua/24243646029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23871, 'El Pilar 1942', 'Imagen parcial de la nueva gran plaza del Pilar desde el entorno de la desaparecida plaza de Huesca. A la izquierda, el provisional solar entre el templo y la recientemente terminada Hospederâ”œÂ¡a del Pilar (fuera de plano), donde estaba previsto construir la nueva Casa de Infantes, y viviendas del Cabildo metropolitano. A la derecha, los â”œÃ­rboles de la antigua plaza del Pilar. En el centro, la genuina primera torre, denominada de Santiago.comenzada en 1715, y terminada en 1892. Fuente visual: www.todocoleccion.net/', 1942, 1942, 1942, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65683300, -0.87974300, '0101000020E61000005551BCCADA26ECBF7FF78E1A13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30861079202.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30861079202.webp', 'https://www.flickr.com/photos/zaragozaantigua/30861079202/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23885, 'Pl. del Pilar 1954', 'Imagen capturada, posiblemente desde la altura del reciente convento de las Hijas de la Caridad de Santa Ana, con interesante vista de la plaza del Pilar, destacando el inmediato gran solar entre la plaza y la calle de las Danzas, reservado para la construcciâ”œâ”‚n del gran edificio de los juzgados. A la derecha, el antiguo emboque a la calle de los Convertidos. Fuente visual: postal de Garcâ”œÂ¡a Garrabella, en www.todocoleccion.net/', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65657100, -0.88012800, '0101000020E610000088670932022AECBF4240BE840AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31704671480.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31704671480.webp', 'https://www.flickr.com/photos/zaragozaantigua/31704671480/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23905, 'Plaza del Pilar 1990', 'Imagen capturada durante las obras de rehabilitaciâ”œâ”‚n y embellecimiento de la plaza del Pilar que entre 1990 (tras las Fiestas del Pilar) y 1991 (antes de las elecciones municipales de finales del mes de mayo) transformaron la denominada "plaza de las Catedrales" en el postmoderno "salâ”œâ”‚n de la ciudad". En esta fotografâ”œÂ¡a, maquinaria de obra extrae â”œÃ­ridos en el subsuelo delimitado entre la Hospederâ”œÂ¡a del Pilar (izquierda) y los Juzgados (derecha) al objeto de permitir luego la construcciâ”œâ”‚n del homâ”œâ”‚nimo aparcamiento. Detrâ”œÃ­s, los accesos al Pilar permanecen siempre despejados en el tramo de la plaza que fuera el original tamaâ”œâ–’o de la misma. Al fondo, pluma de obra en la plaza de la Seo.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65682700, -0.87993500, '0101000020E61000006362F3716D28ECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50457850423.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50457850423.webp', 'https://www.flickr.com/photos/zaragozaantigua/50457850423/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23955, 'El Justicia Lanuza 1591', 'El Justicia Lanuza en el cadalso. Victoriano Balasanz, 1886, Ayuntamiento de Zaragoza. 20 de diciembre de 1591. El joven Justicia Juan de Lanuza se dispone a ser decapitado en la plaza del Mercado por orden de Felipe II. Al fondo, el torreâ”œâ”‚n de la Zuda.', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65684100, -0.88225300, '0101000020E61000004C88B9A46A3BECBF02D6AA5D13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14808150707.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14808150707.webp', 'https://www.flickr.com/photos/zaragozaantigua/14808150707/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24023, 'Calle Murallas Romanas 1985', '1985. Es domingo y dâ”œÂ¡a de San Blas: en el entorno donde despuâ”œÂ®s se colocarâ”œÃ­ la estatua de Câ”œÂ®sar Augusto, con la calle de las Murallas Romanas al fondo, el nâ”œâ•‘mero de la cabra. El solar tras el domador de la trompeta debajo del brazo, a la espera de ser reconstruido. A la izquierda, restos de la muralla y San Juan de los Panetes. Fuente: Colecciâ”œâ”‚n Marâ”œÂ¡a Tausiet, aportada en exclusiva para el Gran Archivo Zaragoza Antigua (GAZA)', 1985, 1985, 1985, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65674400, -0.88225400, '0101000020E6100000637C98BD6C3BECBF10ECF82F10D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24734691925.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24734691925.webp', 'https://www.flickr.com/photos/zaragozaantigua/24734691925/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24048, 'Plaza del Pilar 2002', 'El domingo 26 de noviembre de 1989, dâ”œÂ¡a de Cristo Rey, un grupo de catâ”œâ”‚licos tradicionalistas se reuniâ”œâ”‚ en el Alcâ”œÃ­zar de Toledo, para conmemorar el 14 centenario del Tercer Concilio de Toledo, celebrado en 589, donde se pasâ”œâ”‚ del arrianismo al catolicismo. Estas jornadas se fueron repitiendo: al aâ”œâ–’o siguiente en El Escorial, y por fin, asentâ”œÃ­ndose en Zaragoza, entre 1992 y 2016 ininterrumpidamente. En esta ciudad contaron con el apoyo del arzobispo Manuel Ureâ”œâ–’a (2005-2014), que celebraba una misa exclusiva. Los convocantes, Junta Nacional para la Reconquista de la Unidad Catâ”œâ”‚lica, aglutinan a otras formaciones como Uniones Seglares, Misioneras Rurales, Adoraciâ”œâ”‚n Nocturna, Movimiento Catâ”œâ”‚lico Espaâ”œâ–’ol, Gerona Inmortal o Adveniat Hispania. En la foto, el grupo de las XIII Jornadas de la Unidad Catâ”œâ”‚lica, celebradas en 2002, posando ante el Pilar con algunos sâ”œÂ¡mbolos fascistas. Fuente: Revista Siempre P''alante, 2002.', 2002, 2002, 2002, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65698700, -0.88024000, '0101000020E61000007B319413ED2AECBFD672672618D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31098286140.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31098286140.webp', 'https://www.flickr.com/photos/zaragozaantigua/31098286140/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24102, 'Pl. del Justicia 1918', 'Imagen capturada en la plaza del Justicia abarrotada durante la salida de la iglesia de San Cayetano en fâ”œÂ®retro descubierto de los restos mortales del prelado de Huesca doctor Mariano Supervâ”œÂ¡a Lostalâ”œÂ®, donde estuvo depositado entre el 19 y el 20 de enero de 1918 para recibir el homenaje de los feligreses de la ciudad, camino de la estaciâ”œâ”‚n ferroviaria de Campo Sepulcro para llevarle de regreso a Tauste y ser allâ”œÂ¡ finalmente inhumado en la capilla de Nâ”¬Â¬. Sâ”¬Â¬. de Sancho Abarca de la iglesia de Santa Marâ”œÂ¡a. La comitiva fâ”œâ•‘nebre, por disposiciâ”œâ”‚n del rey Alfonso XIII, presenta la parafernalia y honores propios de un capitâ”œÃ­n general del Ejâ”œÂ®rcito "que muere en plaza donde tiene mando como jefe". Al fondo de la escena, fachada de la iglesia de San Cayetano.', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65609600, -0.88166300, '0101000020E6100000E3FBE2529536ECBFA98427F4FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51435863573.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51435863573.webp', 'https://www.flickr.com/photos/zaragozaantigua/51435863573/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24103, 'Calle de la Manifestaciâ”œâ”‚n 1918', 'Imagen capturada desde cierta altura del cortejo que procesionaba el fâ”œÂ®retro descubierto con los restos mortales del prelado de Huesca doctor Mariano Supervâ”œÂ¡a Lostalâ”œÂ®, desde la iglesia de San Cayetano y hasta la estaciâ”œâ”‚n ferroviaria de Campo Sepulcro para llevarle de regreso a la localidad de Tauste (donde habâ”œÂ¡a nacido en 1835) y ser allâ”œÂ¡ finalmente inhumado en la capilla de Nâ”¬Â¬. Sâ”¬Â¬. de Sancho Abarca de la iglesia de Santa Marâ”œÂ¡a. La comitiva fâ”œâ•‘nebre, que proviene de la inmediata plaza del Justicia, por disposiciâ”œâ”‚n del rey Alfonso XIII presenta la parafernalia y honores propios de un capitâ”œÃ­n general del Ejâ”œÂ®rcito "que muere en plaza donde tiene mando como jefe". Al fondo y a la izquierda, esquinero inmueble del nâ”¬â•‘ 40-46 (actual nâ”¬â•‘ 16) de la calle de la Manifestaciâ”œâ”‚n proyectado por el arquitecto Julio Bravo Folch, en cuyos bajos se ubicaban los almacenes de tejidos de la Viuda de Antonio Ferrer y Bergua.', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65613600, -0.88132000, '0101000020E61000006BF12900C633ECBF37DDB243FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51453386566.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51453386566.webp', 'https://www.flickr.com/photos/zaragozaantigua/51453386566/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24249, 'Calle del Buen Pastor 1960', 'Imagen capturada en la puerta del Colegio Central de Santo Tomâ”œÃ­s de Aquino en su original ingreso por la calle del Buen Pastor nâ”¬â•‘ 1. Este inmueble conformaba las traseras de la antigua casa de los condes de Sobradiel, y era alquilado como parte independiente de â”œÂ®sta. Tras la clausura de una Academia de Enseâ”œâ–’anza Primaria y Secundaria aquâ”œÂ¡ ubicada, Miguel Labordeta Palacios y Anselmo Gascâ”œâ”‚n de Gotor establecieron en 1920 el Colegio de Santo Tomâ”œÃ­s de Aquino, que perdurâ”œâ”‚ hasta el curso 1959-60, cuando desde la Inspecciâ”œâ”‚n de Enseâ”œâ–’anza Media se considerâ”œâ”‚ que el colegio no cumplâ”œÂ¡a las exigencias mâ”œÂ¡nimas para impartir clases. Cerrâ”œâ”‚, pues, en la calle del Buen Pastor para abrir en dos nuevas localizaciones: el paseo de Ruiseâ”œâ–’ores nâ”¬â•‘ 39 para el bachillerato masculino, y la calle de Gil de Jasa nâ”¬â•‘ 24 para el bachillerato femenino. De esta forma, el Colegio Notarial sito desde los aâ”œâ–’os treinta en la zona noble de la antigua casa de los Sobradiel de la plaza del Justicia, por fin consiguiâ”œâ”‚ su anhelo de expandirse, trasladando el archivo notarial y la biblioteca donde estuviera el Colegio Central de Santo Tomas de Aquino, si bien mantuvo el internado y la Enseâ”œâ–’anza Primaria. En la imagen, el co-director Manuel Labordeta Subâ”œÂ¡as escenifica simbâ”œâ”‚licamente el cierre del colegio. Era director del colegio femenino abierto en 1954 en la calle de Espoz y Mina nâ”¬â•‘ 8, luego trasladado al nuevo colegio de la calle Gil de Jasa nâ”¬â•‘ 24. Tras la muerte de su hermano Miguel en 1969 y hasta 1983, aâ”œâ–’o de su propia muerte, ejerciâ”œâ”‚ de director ya en solitario. Manuel Labordeta tambiâ”œÂ®n es recordado como actor y director de cine amateur en la Zaragoza de la â”œÂ®poca. Fuente visual: "Grabado en la mente. Historia del Colegio Santo Tomaâ• Ã¼s Aquino de Zaragoza", Santiago Sancho Vallestâ”œÂ¡n.', 1960, 1960, 1960, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65617800, -0.88237000, '0101000020E6100000B1169F02603CECBF662D05A4FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45470432001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45470432001.webp', 'https://www.flickr.com/photos/zaragozaantigua/45470432001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24350, 'San Cayetano 1930', '"Iglesia de San Cayetano". (Iglesia de Santa Isabel de Portugal).', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65584700, -0.88185100, '0101000020E6100000973C9E961F38ECBF011764CBF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14852314436.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14852314436.webp', 'https://www.flickr.com/photos/zaragozaantigua/14852314436/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24357, 'Murallas romanas c.1954', 'Foto coloreada de una vista de las conocidas popularmente como "murallas romanas" de Zaragoza, en torno a 1955. Se trata del tramo de muralla monumentalizado entre 1946 y 1952 de la zona del torreâ”œâ”‚n de la Zuda (a la izquierda). Se distingue al fondo la pasarela peatonal sobre el Ebro, y se pueden ver las torres de San Juan de los Panetes, del Pilar (en construcciâ”œâ”‚n), la Cruz de los Caâ”œÂ¡dos y la estatua de Câ”œÂ®sar Augusto. Fuente visual: J. R. Tenas.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65692600, -0.88178300, '0101000020E61000008C6665FB9037ECBF30F2B22616D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14974873499.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14974873499.webp', 'https://www.flickr.com/photos/zaragozaantigua/14974873499/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24363, 'Pl. de Huesca 1931', 'Foto: Miguel Marâ”œÂ¡n Chivite. Vista de la plaza de Huesca de Zaragoza, hoy integrada en la del Pilar. Al fondo, la torre de la iglesia de San Juan de los Panetes. El lugar era punto de encuentro de prostitutas y sus prostituidores, incluyendo las calles anexas del Fin, del Pez, de la Zuda, de los Convertidos, de las Danzas y de la Regla. Fuente: Heraldo de Aragâ”œâ”‚n.', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65714300, -0.88064800, '0101000020E6100000B935E9B6442EECBFCDE506431DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15128603826.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15128603826.webp', 'https://www.flickr.com/photos/zaragozaantigua/15128603826/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24378, 'Pl. de San Cayetano 1925', 'Plaza de San Cayetano. Dibujo de Durbâ”œÃ­n. Heraldo de Aragâ”œâ”‚n, 16-4-1925. Vista de la plaza de San Cayetano (hoy del Justicia) de Zaragoza, en 1925. Al fondo, la iglesia de Santa Isabel o San Cayetano. Fuente: Eloy Fernâ”œÃ­ndez Clemente, "Gente de orden", Ibercaja, 1996.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65614300, -0.88157800, '0101000020E610000056F0DB10E335ECBFEA3F6B7EFCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19662249343.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19662249343.webp', 'https://www.flickr.com/photos/zaragozaantigua/19662249343/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24388, 'Pl. de San Cayetano c.1920', 'Plaza de San Cayetano, luego del Justicia, con la iglesia de Santa Isabel o San Cayetano al fondo. Fuente: Foto Jesâ”œâ•‘s Cormâ”œÃ­n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65619900, -0.88150300, '0101000020E6100000AD6D8AC74535ECBF7E552E54FED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24289414943.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24289414943.webp', 'https://www.flickr.com/photos/zaragozaantigua/24289414943/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24397, 'Iglesia del Temple 1991', 'La iglesia de Santa Marâ”œÂ¡a del Temple (1204) formaba parte del convento de la Orden del Temple que se estableciâ”œâ”‚ en el siglo XII en Zaragoza. Su planta era circular, siguiendo la pauta de las iglesias templarias. Su acceso estaba situado en el actual nâ”œâ•‘mero 20 de la calle del Temple, cercano a la plaza del Justicia. Durante el siglo XIX fue desamortizada, usada como almacâ”œÂ®n y finalmente derribada. En 1991 se realizaron excavaciones arqueolâ”œâ”‚gicas que desenterraron los vestigios del templo, momento que recoge la fotografâ”œÂ¡a. 1. Estructura circular interior de la iglesia (edâ”œÂ¡culo). 2. Sillares de muro de una vivienda romana. 3. Restos de pavimento de "opus spicatum". 4. Nivel de construcciâ”œâ”‚n de la vivienda edificada tras la reconquista de la ciudad (principios del siglo XII) y sobre la que se levantâ”œâ”‚ la iglesia. Fuente: Servicios arqueolâ”œâ”‚gicos municipales de Zaragoza, 11 de diciembre de 1991.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65579800, -0.88147100, '0101000020E6100000D5EAABAB0235ECBF1F645930F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27605819284.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27605819284.webp', 'https://www.flickr.com/photos/zaragozaantigua/27605819284/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24426, 'Calle de Salduba c.1951', 'Imagen centrada en el nuevo edificio de la Tienda Econâ”œâ”‚mica y el convento de las Hijas de la Caridad de Santa Ana, proyectado en la esquinera ubicaciâ”œâ”‚n entre la nueva gran plaza del Pilar (a la izquierda) y la moderna calle de Salduba. Destacan en su fachada principal los barrocos restos del ingreso a la casa de los Salavert o Sora, ennoblecidos en el siglo XVII como marqueses de Torrecilla, originalmente en una recoleta ubicaciâ”œâ”‚n de la calle de Santo Dominguito, derribada durante el despeje para abrir la nueva calle de San Vicente de Paâ”œâ•‘l. A la izquierda y hacia el fondo destacan algunas de los inmuebles en el entorno del acceso a la calle de los Convertidos, luego derribados para dejar paso al edificio de los Juzgados y Magistratura de Trabajo de Zaragoza. Una seâ”œâ–’oras pasean, tambiâ”œÂ®n a la izquierda, junto al "Altar de la Patria" o "Monumento a los hâ”œÂ®roes y mâ”œÃ­rtires de Zaragoza. Caâ”œÂ¡dos en la Cruzada de Liberaciâ”œâ”‚n 1936-1939", aâ”œâ•‘n sin terminar.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65688100, -0.88085800, '0101000020E61000006170CD1DFD2FECBF902E36AD14D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49610166088.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49610166088.webp', 'https://www.flickr.com/photos/zaragozaantigua/49610166088/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20871, 'Dominguito y Albayuceto 1250', 'El niâ”œâ–’o de siete aâ”œâ–’os Dominguito de Val, infantico (monaguillo cantante) de la Seo, fue raptado por el judâ”œÂ¡o Albayuceto, que lo entregâ”œâ”‚ a sus correligionarios para que lo crucificaran (en el palacio de Sora o Salabert). Luego ocultaron su cuerpo en la ribera del Ebro tras cortarle los pies y la cabeza. Unas luces divinas mostraron el lugar a unos barqueros, que recuperaron el cuerpo. Esta leyenda fue creada casi cuatro siglos despuâ”œÂ®s de los fantâ”œÃ­sticos eventos, en 1643, a imitaciâ”œâ”‚n de otras similares de marcado tono antisemita. Al fondo, la Seo. Fuente visual: Museo de Huesca, segunda mitad siglo XVII.', 1250, 1250, 1250, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65359500, -0.87397400, '0101000020E6100000DCBC715298F7EBBF21EA3E00A9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15208834552.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15208834552.webp', 'https://www.flickr.com/photos/zaragozaantigua/15208834552/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24431, 'Plaza del Justicia c.1885', 'Interesante imagen de la plaza o plazuela del Justicia capturada desde la altura del nâ”¬â•‘ 27 de la calle de la Manifestaciâ”œâ”‚n. Centra la escena la fachada de la barroca Real capilla de santa Isabel, vulgo de san Cayetano. A la derecha, la calle del Buen Pastor (antigua que desde la plaza del Justicia va hasta la Subida de Botoneros), vista parcial de la Delegaciâ”œâ”‚n provincial de Hacienda ubicada donde estuviera el antiguo convento de los Teatinos de san Cayetano. A la izquierda, el inmueble del nâ”¬â•‘ 3 de la plaza, donde luce el cartelâ”œâ”‚n del nuevo comercio de ultramarinos de la Viuda de Pueyo y de Vicente Lâ”œâ”‚bez al que se entraba por el nâ”¬â•‘ 25 de la calle del Temple, mientras que por el nâ”¬â•‘ 3 se accedâ”œÂ¡a al Gran Almacâ”œÂ®n de Vinos y Licores de esos mismos propietarios, que en su publicidad incluâ”œÂ¡an ese aâ”œâ–’o una oportunista referencia a que "Contra el câ”œâ”‚lera: ajenjo, cognac y rom de la Jamaica". Toma ya. Por encima del inmueble emerge la Torre Nueva de la plaza de San Felipe, desmochada unos aâ”œâ–’os antes e irremediablemente encaminada a su derribo unos aâ”œâ–’os despuâ”œÂ®s. En primer tâ”œÂ®rmino destaca el adoquinado parcial de la plaza, terminado en 1875 y conducente a facilitar el ingreso a la iglesia.', 1885, 1885, 1885, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65603200, -0.88189900, '0101000020E6100000DA006C408438ECBF939048DBF8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52289556348.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52289556348.webp', 'https://www.flickr.com/photos/zaragozaantigua/52289556348/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24436, 'Plaza del Mercado 1884', 'Archivo Municipal de Zaragoza. Colecciâ”œâ”‚n Barnola. Hacia 1880. "Mercado". Imagen de la Plaza del Mercado, en la estaciâ”œâ”‚n sin toldos. Al fondo, la câ”œâ•‘pula de la iglesia de Santiago el Mayor.', 1884, 1884, 1884, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65656900, -0.88261800, '0101000020E6100000B98C9B1A683EECBFA148F7730AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14822735718.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14822735718.webp', 'https://www.flickr.com/photos/zaragozaantigua/14822735718/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24438, 'Calle del Mercado c.1877', 'Calle del Mercado. Al fondo, el Torreâ”œâ”‚n de la Zuda. Fuente: Archivo RUIZ VERNACCI, Jean Laurent y Câ”œÂ¡a. 1872-1879.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65655300, -0.88225900, '0101000020E6100000D540F339773BECBF9C8BBFED09D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14866028465.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14866028465.webp', 'https://www.flickr.com/photos/zaragozaantigua/14866028465/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24440, 'Mercado de Zaragoza 1896', 'Joaquâ”œÂ¡n Pallarâ”œÂ®s: Mercado de Zaragoza, â”œâ”‚leo sobre tela. Representaciâ”œâ”‚n de la antigua plaza del Mercado de Zaragoza, posiblemente la zona de los puestos cercanos a la calle de la Torre Nueva, a la derecha. Aâ”œâ–’os despuâ”œÂ®s, con la construcciâ”œâ”‚n del gran y modernista Nuevo Mercado, este entorno serâ”œÂ¡a radicalmente transformado. Este cuadro fue expuesto en 1896 en la "Tercera Exposiciâ”œâ”‚n de Bellas Artes e Industrias Artâ”œÂ¡sticas de Barcelona" donde recibiâ”œâ”‚ uno de los primeros premios y fue adquirido para una colecciâ”œâ”‚n particular por 2.500 pesetas. En la actualidad estâ”œÃ­ expuesto en el Museo Nacional de Arte de Cataluâ”œâ–’a,', 1896, 1896, 1896, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65600600, -0.88280600, '0101000020E61000006CCD565EF23FECBF69FD2D01F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14895521993.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14895521993.webp', 'https://www.flickr.com/photos/zaragozaantigua/14895521993/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24443, 'Calle de Predicadores 1965', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Setiembre 1965. "Fotos de fachadas y portales." Imagen de la calle Predicadores 6, 8 y 10, inmuebles luego derribados. En la planta calle del nâ”œâ•‘mero 10, un comercio de aperos y artilugios propios de la primera revoluciâ”œâ”‚n neolâ”œÂ¡tica, lo que es todo un elogio: aâ”œâ•‘n no habâ”œÂ¡an sido superados. Dos pisos por arriba, una criatura a la que le han echado la persiana.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65705500, -0.88295100, '0101000020E61000004E0E9F742241ECBF2E56D4601AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15049552929.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15049552929.webp', 'https://www.flickr.com/photos/zaragozaantigua/15049552929/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24453, 'Calle Manifestaciâ”œâ”‚n 1974', 'Foto Antonio Herranz 1974. Dâ”œÂ¡a de lluvia de 1974, visto desde la cafeterâ”œÂ¡a Lanuza, en la esquina de la plaza del mismo nombre con la calle Manifestaciâ”œâ”‚n de Zaragoza. Justo enfrente, calle Salduba, con su churrerâ”œÂ¡a a la izquierda. Tanto la cafeterâ”œÂ¡a como la churrerâ”œÂ¡a, extintas. Fuente: www.facebook.com/photo.php?fbid=380357982121037&set=o...', 1974, 1974, 1974, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65651100, -0.88203600, '0101000020E610000006A1BC8FA339ECBF6D3B6D8D08D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15832794146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15832794146.webp', 'https://www.flickr.com/photos/zaragozaantigua/15832794146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24663, 'Calle Antonio Pâ”œÂ®rez 1889', 'J. Lâ”œÂ®vy et Cie, 1889 Calle de Antonio Pâ”œÂ®rez, hoy avenida Câ”œÂ®sar Augusto. Torreâ”œâ”‚n de la Zuda.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65702100, -0.88186800, '0101000020E610000019726C3D4338ECBF82E49D4319D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14991359335.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14991359335.webp', 'https://www.flickr.com/photos/zaragozaantigua/14991359335/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24668, 'Murallas romanas 1987', 'Foto Rogelio Allepuz. Vista de las murallas romanas de Zaragoza, con la iglesia de San Juan de los Panetes y su torre en restauraciâ”œâ”‚n, al fondo. En primer plano, soâ”œâ–’ador poblador. Fuente: www.facebook.com/photo.php?fbid=428574137238890&set=p...', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65705700, -0.88202900, '0101000020E610000066F4A3E19439ECBFCF4D9B711AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15824921956.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15824921956.webp', 'https://www.flickr.com/photos/zaragozaantigua/15824921956/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24678, 'Calle Prudencio 1977', 'Imagen de la calle de Prudencio, con vista parcial de los vestigios edilicios de la derecha, apenas ya el lienzo de la planta calle, que se corresponden con el tramo entre los antiguos nâ”œâ•‘meros 23 y 33 de la manzana delimitada por las calles Danzas, Convertidos, Prudencio, y la Virgen, esta â”œâ•‘ltima, al fondo. Sobre estos solares, al principio de la dâ”œÂ®cada de los aâ”œâ–’os 90 se realizâ”œâ”‚ una importante ampliaciâ”œâ”‚n de los Juzgados de la plaza del Pilar. En uno de los portales de la imagen quedan vestigios de un antiguo despacho, posiblemente, de "carbâ”œâ”‚n mineral y vegetal". Fuente visual: amable aportaciâ”œâ”‚n personal de Pablo Valdâ”œÂ®s.', 1977, 1977, 1977, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65621000, -0.88079300, '0101000020E61000009B7631CD742FECBF72A774B0FED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26557500921.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26557500921.webp', 'https://www.flickr.com/photos/zaragozaantigua/26557500921/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24682, 'Pl. de San Antonio Abad 1925', 'Imagen capturada durante la ceremonial entrada en la ciudad del nuevo arzobispo, Rigoberto Domâ”œÂ®nech Valls, sobre preceptiva y albina caballerâ”œÂ¡a. La oficial comitiva, de la que forman parte las primeras autoridades municipales, transita por el arranque de la calle de la Manifestaciâ”œâ”‚n, a la altura de la antigua plaza de San Antonio Abad, espacio ocupado durante siglos por el convento de San Antonio Abad, o San Antâ”œâ”‚n, desde donde se podâ”œÂ¡a acceder al antiguo palacio de la Castellanâ”œÂ¡a de Amposta, y a la iglesia de San Juan de los Panetes. Fuente visual: colecciâ”œâ”‚n Francisco Gâ”œâ”‚rriz, en AMZ.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65660000, -0.88201800, '0101000020E61000006C770FD07D39ECBFDC4603780BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33732221366.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33732221366.webp', 'https://www.flickr.com/photos/zaragozaantigua/33732221366/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24684, 'Avenida Câ”œÂ®sar Augusto 2012', 'Foto: Oliver Duch. Vista en marzo de 2012 de la avenida de Câ”œÂ®sar Augusto durante las obras de la segunda fase de la lâ”œÂ¡nea 1 del tranvâ”œÂ¡a. A la izquierda, iglesia de San Juan de los Panetes y murallas romanas. Al fondo, torres del Pilar. A la derecha, estatua de Câ”œÂ®sar Augusto y "Alegorâ”œÂ¡a de la Puerta de la Paz" (1989-2013). Fuente: Heraldo de Aragâ”œâ”‚n.', 2012, 2012, 2012, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65693400, -0.88220000, '0101000020E610000097FF907EFB3AECBFB3D0CE6916D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39763283425.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39763283425.webp', 'https://www.flickr.com/photos/zaragozaantigua/39763283425/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
