INSERT INTO public.photos VALUES (24916, 'Câ”œÂ®sar Augusto 1999', 'Despuâ”œÂ®s de tres meses ausente de su emplazamiento, la estatua de Câ”œÂ®sar Augusto vuelve al conjunto monumental cercano al tramo de las Murallas Romanas junto al Mercado Central, donde se ubica desde 1990. Habâ”œÂ¡a estado en Mâ”œÂ®rida para hacerle una copia. Fuente: Agencia EFE.', 1999, 1999, 1999, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65674400, -0.88225400, '0101000020E6100000637C98BD6C3BECBF10ECF82F10D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24335602140.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24335602140.webp', 'https://www.flickr.com/photos/zaragozaantigua/24335602140/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
