INSERT INTO public.photos VALUES (25104, 'Caballero cadete, 1957', 'Imagen de su alteza real el caballero cadete Juan Carlos de Borbâ”œâ”‚n y Borbâ”œâ”‚n capturada en la plaza del Pilar durante una revista militar. Entre 1955 y 1957 Juan Carlos formâ”œâ”‚ parte de la XIV promociâ”œâ”‚n de la Academia General Militar, de la que saliâ”œâ”‚ con el grado de alfâ”œÂ®rez de infanterâ”œÂ¡a. Al fondo, gran solar resultante del derribo de la manzana entre las calles de la Regla y de Prudencio, cuyo tramo hasta la calle de la Virgen queda, por ello, visible desde la plaza. A la derecha y fuera de plano, el Altar de la Patria o Monumento a los hâ”œÂ®roes y mâ”œÃ­rtires de Zaragoza caâ”œÂ¡dos en la Cruzada de Liberaciâ”œâ”‚n 1936-1939.', 1957, 1957, 1957, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65693000, -0.88048300, '0101000020E610000011E335AFEA2CECBF72E1404816D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50894093206.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50894093206.webp', 'https://www.flickr.com/photos/zaragozaantigua/50894093206/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25383, 'Los â”œâ•‘ltimos momentos de Lanuza 1591', 'Los â”œâ•‘ltimos momentos de Lanuza, â”œâ”‚leo sobre lienzo, Eduardo Lâ”œâ”‚pez del Plano, Diputaciâ”œâ”‚n de Zaragoza, 1864. Juan de Lanuza, Justicia de Aragâ”œâ”‚n, va a ser decapitado por orden de Felipe II en la plaza del Mercado de Zaragoza. A la derecha, la Câ”œÃ­rcel de la Manifestaciâ”œâ”‚n y la Puerta de Toledo, derruidas en 1848. Al fondo, el Torreâ”œâ”‚n de la Zuda. Fuente: web.dpz.es/arscatalogi.es/', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65661600, -0.88220000, '0101000020E610000097FF907EFB3AECBFE2033BFE0BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15255817173.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15255817173.webp', 'https://www.flickr.com/photos/zaragozaantigua/15255817173/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25384, 'Pl. del Justicia 1966', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 08/04/1966. La monumental fachada de la barroca iglesia de Santa Isabel de Portugal, o San Cayetano, es excepcional por su riqueza y profusiâ”œâ”‚n decorativa. Las airosas torres delimitan una estructura vignolesca enmascarada por recargada ornamentaciâ”œâ”‚n y decoraciâ”œâ”‚n abigarrada, de estilo churrigueresco, â”œâ•‘nica en la ciudad. Alcanza efectos cromâ”œÃ­ticos insâ”œâ”‚litos mediante la combinaciâ”œâ”‚n de materiales como piedra negra para los elementos arquitectâ”œâ”‚nicos, piedra ocre para los decorativos, y alabastro blanco para el fondo. El escudo herâ”œÃ­ldico de Aragâ”œâ”‚n preside la entrada, flanqueada por las estatuas, a la izquierda la de San Andrâ”œÂ®s Avelino (de los Clâ”œÂ®rigos Regulares o teatinos) y a la derecha la de San Cayetano (fundador de los Clâ”œÂ®rigos Regulares Teatinos). En la hornacina superior estâ”œÃ­ la titular de la iglesia (Santa Isabel de Portugal), representada con el manto entreabierto para dejar asomar unas rosas. En la imagen, nocturna vista de la fachada de la iglesia, desde la plaza del Justicia. Como es abril, hay seâ”œâ–’ores y niâ”œâ–’os disfrazados en medio.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65584700, -0.88185100, '0101000020E6100000973C9E961F38ECBF011764CBF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15278515585.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15278515585.webp', 'https://www.flickr.com/photos/zaragozaantigua/15278515585/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25385, 'Puerta de Toledo c.1840', '"Desfile jocoso con novillos", lâ”œÃ­piz y acuarela sobre papel, anâ”œâ”‚nimo, Museo de Zaragoza. Festejo popular con novillos cabalgados por actores disfrazados en la plaza del Mercado. Al fondo a la izquierda, la puerta de San Ildefonso y el Torreâ”œâ”‚n de la Zuda. A la derecha, las ruinas de la Puerta de Toledo, ordenada derribar en 1842. Fuente visual: El coso de la Misericordia de Zaragoza (2014).', 1840, 1840, 1840, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65651100, -0.88203600, '0101000020E610000006A1BC8FA339ECBF6D3B6D8D08D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15457827898.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15457827898.webp', 'https://www.flickr.com/photos/zaragozaantigua/15457827898/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25387, 'Personal Jesus 1965', 'Archivo Municipal. Gerardo Sancho Ramo. 1965. "Procesiones de Semana Santa". "Your own, personal Jesus, someone to hear your prayers, someone who cares. Your own, personal Jesus, someone to hear your prayers, someone who''s there." "Personal Jesus", Depeche Mode (Violator, 1990). Penitente descalzo con mono de faena en funciones propias del Nazareno, iniciando calvario tras salir de la iglesia de Santa Isabel (derecha), en la plaza del Justicia. La calle del fondo es Santa Isabel. Va camino de Manifestaciâ”œâ”‚n. Mujeres expectantes.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65589500, -0.88147000, '0101000020E6100000BEF6CC920035ECBF124E0B5EF4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15898684026.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15898684026.webp', 'https://www.flickr.com/photos/zaragozaantigua/15898684026/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25391, 'Puerta de la Paz 2012', 'En 1989 se construyâ”œâ”‚ este conjunto, denominado "Alegorâ”œÂ¡a de la Puerta de la Paz", obra de Juan Martâ”œÂ¡n Trenor, en el lugar donde se ubicaba la Puerta de Toledo. Fue derribado en 2013, en el marco de las obras de la lâ”œÂ¡nea 1 del nuevo tranvâ”œÂ¡a. La estatua de Câ”œÂ®sar Augusto permanece. Fuente: www.fotonazos.es/2012/01/alegoria-de-la-puerta-de-la-paz-...', 2012, 2012, 2012, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65661600, -0.88220000, '0101000020E610000097FF907EFB3AECBFE2033BFE0BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18459101003.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18459101003.webp', 'https://www.flickr.com/photos/zaragozaantigua/18459101003/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25394, 'Pl. de Lanuza 1967', 'Esquina de la plaza de Lanuza con la calle de Predicadores (derecha). Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65680000, -0.88264000, '0101000020E6100000AD86C43D963EECBFA301BC0512D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22777943419.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22777943419.webp', 'https://www.flickr.com/photos/zaragozaantigua/22777943419/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25397, 'Murallas Romanas 1964', 'De buena maâ”œâ–’ana, un marzo que "marzeaba" lo normal, y sin cierzo, Gerardo Sancho ascendiâ”œâ”‚ al Torreâ”œâ”‚n de la Zuda, a verlas pasar (las imâ”œÃ­genes), y en el momento preciso, capturâ”œâ”‚ esta, que con el tiempo se ha convertido en una visual estâ”œÃ­ndar. Centra la toma el recreado paâ”œâ–’o de las defensas romanas donde se levantara la antigua puerta este de la ciudad, luego Bab Qala''ath, luego de Toledo. A la izquierda, el itâ”œÃ­lico y semoviente Câ”œÂ®sar Augusto, en uno de sus sitiales provisionales, presidiendo una plaza en su imperial honor, y en construcciâ”œâ”‚n. Al fondo, el Mercado Central, aâ”œâ•‘n eclipsado por los restos decimonâ”œâ”‚nicos de los adosados al gran complejo hospitalario de San Juan. A la derecha, los nâ”œâ•‘meros impares de la antigua calle de la Triperâ”œÂ¡a, luego de Antonio Pâ”œÂ®rez, luego Imperial, luego Vâ”œÂ¡a Imperial, y en unos aâ”œâ–’os, parte de una nueva avenida de Câ”œÂ®sar Augusto, actual denominaciâ”œâ”‚n de esas "de toda la vida". Hacâ”œÂ¡a un par de aâ”œâ–’os que el Ministerio de Obras Pâ”œâ•‘blicas habâ”œÂ¡a aprobado levantar un inmediato y nuevo puente para circulaciâ”œâ”‚n motorizada sobre el Ebro, y sus cimientos ya estaban asentados. Poco tiempo despuâ”œÂ®s, las manzanas de la imagen, entre las calles Predicadores, Aben Aire, y Escobar, serâ”œÂ¡a retranqueadas unos metros para fluidificar el trâ”œÃ­nsito rodado hasta la puerta del Carmen. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1964, 1964, 1964, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65674400, -0.88225400, '0101000020E6100000637C98BD6C3BECBF10ECF82F10D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24397219414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24397219414.webp', 'https://www.flickr.com/photos/zaragozaantigua/24397219414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.8