INSERT INTO public.photos VALUES (25399, 'Câ”œÂ®sar Augusto 2013', 'Foto: Oliver Duch. Instantâ”œÃ­nea tomada el 12 de marzo de 2013, durante las obras de demoliciâ”œâ”‚n de los arcos instalados en 1989 con el nombre de "Alegorâ”œÂ¡a de la Puerta de la Paz". Frente a ellos, la estatua de Câ”œÂ®sar Augusto. Sobre â”œÂ®l, la viga superior de uno de los arcos. Fuente: Heraldo de Aragâ”œâ”‚n.', 2013, 2013, 2013, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65687000, -0.88229600, '0101000020E61000001E882CD2C43BECBF9CDCEF5014D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29908956287.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29908956287.webp', 'https://www.flickr.com/photos/zaragozaantigua/29908956287/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25401, 'Plaza de Lanuza 1966', 'Imagen capturada durante una procesiâ”œâ”‚n, posiblemente, de la cofradâ”œÂ¡a de la Instituciâ”œâ”‚n de la Sagrada Familia, en la antigua plaza de Lanuza. Al fondo, la calle Manifestaciâ”œâ”‚n y la plaza del Justicia (derecha). A la izquierda, los â”œâ•‘ltimos restos edilicios adosados al tramo de las murallas de piedra de San Juan de los Panetes; entre ellos se encontraba el nâ”¬â•‘ 27 de la plaza de Lanuza, donde figuraba la hospederâ”œÂ¡a Caroll y San Jorge. A la derecha, el esquinero edificio en cuyos bajos estaba el cafâ”œÂ® Lanuza. En su fachada, publicidad comercial de los productos lâ”œÃ­cteos "Massanes y Grau", buscando aumentar cuota de mercado tras la entrada de capital suizo. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65660000, -0.88201800, '0101000020E61000006C770FD07D39ECBFDC4603780BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31072174660.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31072174660.webp', 'https://www.flickr.com/photos/zaragozaantigua/31072174660/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25402, 'VIsta aâ”œÂ®rea Mercado c.1968', 'Vista aâ”œÂ®rea parcial del centro histâ”œâ”‚rico de Zaragoza. Arriba, el râ”œÂ¡o Ebro. A la izquierda, el barrio de San Pablo y el Mercado Central. En el centro, la iglesia de Santa Isabel. Abajo, la sombra de la torre de San Felipe se proyecta donde se levantaba la Torre Nueva. Fuente visual: foto Pedro Marco.', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65581200, -0.88197600, '0101000020E6100000B16B7BBB2539ECBF8429CAA5F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32855076964.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32855076964.webp', 'https://www.flickr.com/photos/zaragozaantigua/32855076964/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20971, 'Juslibol y Alfocea 1858', '"Croquis del monte y dehesa que posee el pueblo de Juslibol, empalmando con el terreno que litiga como Pardina de Miranda y sus limâ”œÂ¡trofes". Firmado por Eusebio Blasco y Taula, Geâ”œâ”‚metra y Director de Caminos Vecinales. Archivo Histâ”œâ”‚rico Provincial de Zaragoza, 1858. Plano orientado con el Norte abajo, que incluye los actuales barrios rurales de Juslibol (a la izquierda) y Alfocea (en el centro).', 1858, 1858, 1858, 'Siglo XIX', NULL, 41.69364300, -0.89998100, '0101000020E61000001DAF40F4A4CCECBFB70C384BC9D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19300278255.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19300278255.webp', 'https://www.flickr.com/photos/zaragozaantigua/19300278255/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25404, 'Pl. del Justicia 1967', 'Imagen centrada en la gran fachada clasicista de la casa del siglo XVII de la familia Cavero de Ahones, condes de Sobradiel, tâ”œÂ¡tulo al que desde 1857 se sumâ”œâ”‚ el de barones de Letosa (al aâ”œâ–’o siguiente la casa fue reformada segâ”œâ•‘n proyecto del arquitecto Josâ”œÂ® de Yarza Miâ”œâ–’ana), y desde 1898 el de condes de Gabarda. Desde 1930 este edificio es sede del Ilustre Colegio Notarial de Aragâ”œâ”‚n. A la derecha de la imagen, posiblemente un autobâ”œâ•‘s de la lâ”œÂ¡nea de la Almozara. Fuera de plano y desde 1962 estaba reubicada la fuente de La Samaritana. Fuente visual: fotografâ”œÂ¡a de Guillermo Fatâ”œÃ­s Ojuel en Torralba, Federico; Gâ”œâ”‚mez de Valenzuela, Manuel, Catâ”œÃ­logo de monumentos histâ”œâ”‚ricos-artâ”œÂ¡sticos y edificios de interâ”œÂ®s para el estudio del arte en la ciudad de Zaragoza. Cuadernos de Aragâ”œâ”‚n nâ”¬â•‘ 73, IFC.', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65614600, -0.88190900, '0101000020E6100000BE8921399938ECBF5BB39597FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44913427611.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44913427611.webp', 'https://www.flickr.com/photos/zaragozaantigua/44913427611/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25918, 'Plaza del Mercado c.1900', 'Vista de la plaza del Mercado hacia 1900, con un tranvâ”œÂ¡a (posiblemente, un coche cerrado tipo C) tirado por caballerâ”œÂ¡a de la lâ”œÂ¡nea de Circunvalaciâ”œâ”‚n (inaugurada en 1887 y electrificada en 1903). A la derecha, edificios que luego serâ”œÃ­n derribados para la construcciâ”œâ”‚n del Nuevo Mercado. Al fondo, calle de Antonio Pâ”œÂ®rez.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65651000, -0.88283500, '0101000020E61000000074982F2F40ECBF9CBF098508D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31251720050.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31251720050.webp', 'https://www.flickr.com/photos/zaragozaantigua/31251720050/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26037, 'Vista aâ”œÂ®rea centro 1957', 'Vista aâ”œÂ®rea del centro histâ”œâ”‚rico, con el Pilar y el Ebro a la izquierda. Destaca abajo el alargado Mercado Central. Fuente: TAF Helicâ”œâ–“pters. Arxiu Nacional de Catalunya.', 1957, 1957, 1957, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65609900, -0.87968700, '0101000020E61000005BECF6596526ECBF1AF8510DFBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31213770422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31213770422.webp', 'https://www.flickr.com/photos/zaragozaantigua/31213770422/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20870, 'La Seo româ”œÃ­nica', 'La catedral româ”œÃ­nica de La Seo hacia 1300, segâ”œâ•‘n J. A. Pâ”œÂ®rez Casas sobre datos de B. Cabaâ”œâ–’ero. Fuente: Libro Historia de cuatro ciudades', 1308, 1118, 1499, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65445700, -0.87546200, '0101000020E61000000A815CE2C803ECBFB3D1393FC5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14978662856.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14978662856.webp', 'https://www.flickr.com/photos/zaragozaantigua/14978662856/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20873, 'Mezquita 1119', 'Probable aspecto de la mezquita de Sarakosta en 1119 un momento antes de su consagraciâ”œâ”‚n como catedral, tras la conquista cristiana de la ciudad. En la imagen se han resaltado en color los muros que hoy estâ”œÃ­n visibles, tanto desde el exterior, como desde el interior del templo catâ”œâ”‚lico. Fuente: www.facebook.com/photo.php?fbid=996342230381622&set=p...', 1119, 1119, 1119, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65498300, -0.87590900, '0101000020E6100000C0B4A84F7207ECBFCE37A27BD6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15616159318.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15616159318.webp', 'https://www.flickr.com/photos/zaragozaantigua/15616159318/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20875, 'Crâ”œÃ­neo de San Valero 1170', 'Pintura atribuida al zaragozano Bartolomâ”œÂ® Vicente, de comienzos del siglo XVIII, titulada "Llegada del crâ”œÃ­neo de San Valero a Zaragoza procedente de Roda de Isâ”œÃ­bena", hoy en la capilla de San Valero en la catedral de San Salvador. Este cuadro recrea el retorno a la ciudad del crâ”œÃ­neo del que fuera su obispo allâ”œÃ­ por el siglo IV de la Era. Parece ser que, justo cuando estaba conformâ”œÃ­ndose el primitivo Reino de Aragâ”œâ”‚n, varios siglos despuâ”œÂ®s de su muerte, alguien dio voces de que los restos de San Valero estaban allâ”œÃ­ cerca de Anet (oeste de Parâ”œÂ¡s, Francia), aunque otras fuentes lo sitâ”œâ•‘an en Enate (Barbastro). Se justificâ”œâ”‚ el dislate geogrâ”œÃ­fico con el argumento de que eso era asâ”œÂ¡ porque habrâ”œÂ¡a sido allâ”œÂ¡ exiliado. En 1050, al poco de su "descubrimiento", lo que se identificâ”œâ”‚ cientâ”œÂ¡ficamente como restos de su cuerpo fue llevado a la sede episcopal de Roda de Isâ”œÃ­bena, entonces cabeza eclesial del Reino de Aragâ”œâ”‚n. Cuando las tropas de Alfonso I y de Gastâ”œâ”‚n de Bearne conquistaron Sarakosta en 1118, se requiriâ”œâ”‚ la presencia fâ”œÂ¡sica de las reliquias valerianas en la que fuera su sede episcopal ochocientos aâ”œâ–’os antes. El capâ”œÂ¡tulo de Roda aceptâ”œâ”‚ la cesiâ”œâ”‚n y enviâ”œâ”‚, primero un brazo y, en 1170, el crâ”œÃ­neo del obispo, siendo ya rey el segundo Alfonso. Es lo que representa fielmente el cuadro, unos 530 aâ”œâ–’os despuâ”œÂ®s de los hechos narrados, en composiciâ”œâ”‚n, abigarradas formas y parduzcos colores barrocos, y en un entorno zaragozano poco preciso, cerca de la Seo. El crâ”œÃ­neo parece tener bastante buena cara, a pesar de todo. Fuente visual: "Vicente Berdusâ”œÃ­n (1632Ã”Ã‡Ã´1697). El artista artesano", AA.VV., DPZ, 2006.', 1170, 1170, 1170, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65498300, -0.87590900, '0101000020E6100000C0B4A84F7207ECBFCE37A27BD6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18904769223.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18904769223.webp', 'https://www.flickr.com/photos/zaragozaantigua/18904769223/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20879, 'Zaragoza c.1400', 'Iluminaciâ”œâ”‚n para manuscrito, 1350-1400. Representaciâ”œâ”‚n idealizada de una batalla sin determinar frente a la puerta Norte de Zaragoza (luego del â”œÃ¼ngel) para ilustrar el relato de la historia de los romanos hasta la muerte de Julio Câ”œÂ®sar (44 antes de la Era). Como en otros dibujos similares (verbigracia los referentes al sitio de 542), la estâ”œÂ®tica corresponde a la â”œÂ®poca en que fueron realizados. Fuente: Les anciennes hystoires romaines, ca. 1350-1400, British Library, Londres.', 1400, 1400, 1400, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65605400, -0.87591000, '0101000020E6100000D6A887687407ECBF7A34D593F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20027969505.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20027969505.webp', 'https://www.flickr.com/photos/zaragozaantigua/20027969505/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20880, 'Sello de Zaragoza 1299', 'Representaciâ”œâ”‚n en un sello de cera municipal de la muralla medieval de Zaragoza, en un documento del Cabildo Metropolitano de 1299. La imagen del exterior de la ciudad con sus torreones es similar a la que aparece en esa â”œÂ®poca en otros municipios, por lo que se tratarâ”œÂ¡a de un alzado genâ”œÂ®rico figurado, en todo caso cercano al aspecto de Zaragoza en el siglo XIII. En la parte superior, una cruz patriarcal, de doble travesaâ”œâ–’o, que seâ”œâ–’ala la urbe como sede arzobispal. Abajo, un leâ”œâ”‚n rampante, blasâ”œâ”‚n de Zaragoza. Fuente visual: Catâ”œÃ­logo "El municipio en Aragâ”œâ”‚n", DPZ, 2004.', 1299, 1299, 1299, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65605400, -0.87591000, '0101000020E6100000D6A887687407ECBF7A34D593F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20520454575.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20520454575.webp', 'https://www.flickr.com/photos/zaragozaantigua/20520454575/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20984, 'Pastos de Zaragoza 1803', '"Plano que manifiesta una porciâ”œâ”‚n de terreno comprendido con las tres mojonaciones, las que incluyen las Yerbas o pastos para los ganados de esta Ilustrâ”œÂ¡sima ciudad de Zaragoza", Ambrosio Lanzaco, 1803. Se incluyen los terrenos comprendidos entre el sur de Peâ”œâ–’aflor (arriba) y los montes de Villamayor (abajo). A la izquierda, la Cartuja de Aula Dei y un tramo del râ”œÂ¡o Gâ”œÃ­llego. Fuente: AMZ.', 1803, 1803, 1803, 'Siglo XIX', NULL, 41.72954100, -0.79515100, '0101000020E6100000DB368C82E071E9BFAA0B789961DD4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21034674276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21034674276.webp', 'https://www.flickr.com/photos/zaragozaantigua/21034674276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20881, 'Posesa en la Seo 1170', 'Banco del Retablo Mayor de la Seo de San Salvador (detalle). Pere Joan, Zaragoza, 1434-1440. Momento en el que un demonio en forma de dragâ”œâ”‚n es expulsado por una mujer, en el interior de la Seo de Zaragoza. Al fondo, el busto-relicario de San Valero y, sobre la mesa del altar, el crâ”œÃ­neo del obispo, a cuya intercesiâ”œâ”‚n se atribuyâ”œâ”‚ el milagro de la curaciâ”œâ”‚n. Los clâ”œÂ®rigos testigos del acontecimiento se agrupan a ambos lados del altar: uno de ellos, provisto de lentes, lee un libro de exorcismos, mientras los mâ”œÃ­s cercanos al diablo se tapan la nariz ante el hedor que desprende. Segâ”œâ•‘n Diego de Espâ”œÂ®s, la escena se produjo en 1159; segâ”œâ•‘n Martâ”œÂ¡n Carrillo, en 1170, coincidiendo con la traslaciâ”œâ”‚n del crâ”œÃ­neo de San Valero. El protagonista era un varâ”œâ”‚n, pero el escultor le dio forma femenina, mezclando este suceso con el de una dama de la nobleza que tambiâ”œÂ®n se curâ”œâ”‚ de su posesiâ”œâ”‚n en la Seo, segâ”œâ•‘n Carrillo, entrando a la fuerza "desnuda, con sola la camisa". Fuente: "Los posesos de Tosos", Marâ”œÂ¡a Tausiet, Instituto Aragonâ”œÂ®s de Antropologâ”œÂ¡a, 2002.', 1170, 1170, 1170, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65482800, -0.87568800, '0101000020E61000001EFD2FD7A205ECBFA7406667D1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21558922942.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21558922942.webp', 'https://www.flickr.com/photos/zaragozaantigua/21558922942/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20884, 'La Seo 1397', 'Representaciâ”œâ”‚n de F. Blanch que pretende ilustrar la medieval y ceremonial jura del nuevo rey de Aragâ”œâ”‚n Martâ”œÂ¡n I, tambiâ”œÂ®n llamado el Humano, y aun el Viejo, ante el justiciazgo Juan Jimâ”œÂ®nez Cerdâ”œÃ­n, en la catedral del Salvador de Zaragoza, iluminada para la ocasiâ”œâ”‚n. Mientras, la viuda del difunto rey Juan I (Yolanda de Bar), y aun Mateo I (yerno del mismo), pugnaban tambiâ”œÂ®n por la sucesiâ”œâ”‚n. Ademâ”œÃ­s, eran los tiempos del llamado "Cisma de Occidente", en el que un aragonâ”œÂ®s (Benedicto XIII) no solo era papa, sino que alcanzâ”œâ”‚ el status de antipapa, respaldado fervorosa e interesadamente por el gerundâ”œÂ®s Martâ”œÂ¡n I. Fuente visual: Historia de Espaâ”œâ–’a, Miguel Seguâ”œÂ¡, 1910, en www.delcampe.es', 1397, 1397, 1397, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65472200, -0.87580700, '0101000020E6100000B073D3669C06ECBF61FC34EECDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31616326644.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31616326644.webp', 'https://www.flickr.com/photos/zaragozaantigua/31616326644/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20904, 'Cabalgata universitaria 1588', 'Desarrollo de la cabalgata universitaria de 1588. Francisco Melâ”œÂ®ndez. Boceto para aguafuerte, 1985. En 1583 se fundâ”œâ”‚ la Universidad de Zaragoza. Cinco aâ”œâ–’os despuâ”œÂ®s, el dâ”œÂ¡a de san Braulio (26 de marzo) de 1588, una cabalgata universitaria recorriâ”œâ”‚ las calles de Zaragoza pasando por La Seo, como recoge el dibujo. Historia de Zaragoza', 1588, 1588, 1588, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65509500, -0.87546600, '0101000020E61000006551D845D103ECBFF6622827DAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14835425239.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14835425239.webp', 'https://www.flickr.com/photos/zaragozaantigua/14835425239/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20914, 'Puerta del â”œÃ¼ngel 1564', 'Pintura de Antonio Martâ”œÂ¡nez titulada "Arzobispo Hernando de Aragâ”œâ”‚n, fundador de la Cartuja del Aula Dei, regresa con su sâ”œÂ®quito a la ciudad de Zaragoza". Este pintor posiblemente sea Jerâ”œâ”‚nimo Martâ”œÂ¡nez y Jenequi, hijo de Jusepe Martâ”œÂ¡nez, que tras formarse en la pintura entrâ”œâ”‚ como seglar en la cartuja de Aula Dei en 1665, donde pasâ”œâ”‚ el resto de vida, hasta su muerte en 1690, sin abandonar su dedicaciâ”œâ”‚n artâ”œÂ¡stica. Este cuadro, hoy en manos particulares, habrâ”œÂ¡a sido uno de los realizados durante su estancia cartujana, en composiciâ”œâ”‚n, dibujo, y tâ”œÂ®cnicas que beben claramente de las de su padre, considerado el pintor mâ”œÃ­s importante del siglo XVII en el antiguo Reino de Aragâ”œâ”‚n. En el cuadro, el benefactor arzobispo aparece entre la Cartuja, ya terminada, a la izquierda, y la puerta del â”œÃ¼ngel de Zaragoza, a la derecha. Tras la puerta, la iglesia de San Juan del Puente, y las Casas de la Diputaciâ”œâ”‚n. Fuente visual: "Territorium, el largo camino hacia las comarcas de Aragâ”œâ”‚n", DGA, 2003.', 1564, 1564, 1564, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65605400, -0.87591000, '0101000020E6100000D6A887687407ECBF7A34D593F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18936942313.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18936942313.webp', 'https://www.flickr.com/photos/zaragozaantigua/18936942313/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20921, 'Diputaciâ”œâ”‚n del Reino 1756', '"Perfil de la Casa de la Audiencia de Zaragoza", 1756. Secciâ”œâ”‚n de los edificios de la Diputaciâ”œâ”‚n del Reino en la plaza de la Seo de Zaragoza, con visual de la Puerta del â”œÃ¼ngel desde el interior de la ciudad y la iglesia de San Juan del Puente, cuya torre con veleta era la oriental de la Puerta del â”œÃ¼ngel. Fuente: Archivo General Militar de Madrid. Ministerio de Defensa de Espaâ”œâ–’a.', 1756, 1756, 1756, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65571800, -0.87593500, '0101000020E61000000F7F4DD6A807ECBF03B34291EED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20022230512.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20022230512.webp', 'https://www.flickr.com/photos/zaragozaantigua/20022230512/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22814, 'Calle de la Divisiâ”œâ”‚n Azul 1974', 'Inâ”œÂ®dita imagen capturada en la calle de la Divisiâ”œâ”‚n Azul y centrada en la moderna iglesia de San Josâ”œÂ® Obrero construida a principios de los aâ”œâ–’os 60 durante la segunda fase del Grupo de Viviendas "Josâ”œÂ® Antonio Girâ”œâ”‚n" (por el nombre de este ministro de Trabajo) en el barrio de Las Fuentes, confrontando con el colegio de Santo Domingo de Silos. La singularidad de la fotografâ”œÂ¡a reside en que, ante la total ausencia de los denominados en la â”œÂ®poca "clubs de ancianos" en este barrio de la periferia, muestra a algunos abuelos y abuelas que se congregaban en la fachada de esta iglesia porque su sureâ”œâ–’a orientaciâ”œâ”‚n la convirtiâ”œâ”‚ en una apreciada solanera donde aposentarse durante los meses de invierno para echar el rato. Actualmente, esta es la parroquia de San Josâ”œÂ® Artesano, desde 1986 la calle se denomina de La Amistad, y desde 2009 este grupo de viviendas se conoce como Marâ”œÂ¡a Andrea Casamayor (matemâ”œÃ­tica del siglo XVIII).', 1974, 1974, 1974, 'Anos 70', 'LAS FUENTES', 41.64726200, -0.86031300, '0101000020E6100000535BEA20AF87EBBFC6F8307BD9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51564621644.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51564621644.webp', 'https://www.flickr.com/photos/zaragozaantigua/51564621644/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22977, 'Audiorama 1991', 'Archivo Municipal. Carlos Gil Roig. "Terrenos del Audiorama". A finales de los aâ”œâ–’os 70 del pasado siglo, la necesidad de un nuevo recinto ferial, mâ”œÃ­s amplio y espacioso, llevâ”œâ”‚ a decidir el traslado de la Feria a una nueva ubicaciâ”œâ”‚n. El Pleno de la Câ”œÃ­mara de Comercio e Industria decidiâ”œâ”‚ que serâ”œÂ¡a en la carretera de Madrid, frente a la Venta de los Caballos, colocâ”œÃ­ndose la primera piedra el 10 de abril de 1983, e inaugurâ”œÃ­ndose en octubre de 1986. En la superficie del solar que se abandonaba se edificarâ”œÃ­ el Auditorio-Palacio de Congresos de Zaragoza (inaugurado en octubre de 1994), la Sala Multiusos de Zaragoza, un espacio comercial, los cines Renoir-Audiorama, y la sede logâ”œÂ¡stica de la CAI. La Câ”œÃ­mara de Comercio se reservaba las edificaciones de la esquina Plaza Emperador Carlos-Pâ”¬â•‘ Isabel la Catâ”œâ”‚lica, con la emblemâ”œÃ­tica torre-mirador que simbolizaba al conjunto. En la imagen, aâ”œÂ®rea visual del solar dejado por el derribo del recinto ferial, que desde 1986 y hasta 1990 habâ”œÂ¡a sido utilizado en las Fiestas de octubre como sede de conciertos con la denominaciâ”œâ”‚n de "Pabellâ”œâ”‚n Francâ”œÂ®s", por tener como escenario central un pabellâ”œâ”‚n permanente Hispano-Francâ”œÂ®s construido en 1958, en homenaje a la Expo 1908.', 1991, 1991, 1991, 'Anos 90', 'UNIVERSIDAD', 41.63770500, -0.90032000, '0101000020E61000003AE97DE36BCFECBF72BF4351A0D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15619751322.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15619751322.webp', 'https://www.flickr.com/photos/zaragozaantigua/15619751322/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20926, 'Casas del Reino 1756', 'A mediados del siglo XV fue construido el Palacio de la Diputaciâ”œâ”‚n del General del Reino de Aragâ”œâ”‚n, Palacio de la Diputaciâ”œâ”‚n, o "Casas del Reino", en un espacio de intensa concentraciâ”œâ”‚n de poder institucional laico y religioso: la poderosa catedral del Salvador y el gran palacio Arzobispal (ocasional Residencia Real); la iglesia de San Juan del Puente, las Casas de la Ciudad, y el emergente complejo devocional de Nuestra Seâ”œâ–’ora del Pilar. Inmediata quedaba la puerta de ingreso a la ciudad desde el puente de Piedras, que aâ”œâ–’os despuâ”œÂ®s serâ”œÂ¡a denominada "del â”œÃ¼ngel". Un siglo despuâ”œÂ®s, la Lonja de Mercaderes completarâ”œÂ¡a la densa trama polâ”œÂ¡tico-institucional de este escogido espacio urbano. En las "Casas del Reino" estaba la Audiencia Real, el Justiciazgo, las Cortes, y la Diputaciâ”œâ”‚n, ademâ”œÃ­s de Armerâ”œÂ¡a, Librerâ”œÂ¡a, Archivos, y Oratorio. La Nueva Planta administrativa del Reino de Aragâ”œâ”‚n (abril de 1711), con la reorganizaciâ”œâ”‚n de todos sus â”œâ”‚rganos jurâ”œÂ¡dico-institucionales de gobierno, se realizâ”œâ”‚ sin afecciones a las Casas del Reino. En enero de 1809, durante el breve segundo Sitio francâ”œÂ®s, este palacio resultâ”œâ”‚ muy afectado por el bombardeo, aunque parece ser que no fue reducido a literales "cenizas", con todo su rico patrimonio arquitectâ”œâ”‚nico y artâ”œÂ¡stico, junto con los invaluables y preciosos documentos y legajos de todos sus archivos, como se ha venido repitiendo en la inmensa mayorâ”œÂ¡a de fuentes escritas despuâ”œÂ®s, para las que Zaragoza, tras 1809, quedâ”œâ”‚ completamente arrasada. Segâ”œâ•‘n esa tradicional visiâ”œâ”‚n, tras la graciosa cesiâ”œâ”‚n de este Palacio al Arzobispado de Zaragoza en 1830, por Real Orden firmada por el rey Fernando VII, para levantar allâ”œÂ¡ el nuevo y necesario Seminario Conciliar de San Valero y San Braulio, los operarios constructores se habrâ”œÂ¡an encontrado con un solar quemado, arrasado, y ya casi preparado para cimientos. Parece ser que no fue exactamente asâ”œÂ¡. Sic transit gloria Urbis. En la imagen, plano de la planta calle de las Casas del Reino en 1756. El norte est', 1756, 1756, 1756, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65570500, -0.87596500, '0101000020E6100000B9196EC0E707ECBF6E693524EED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23995903013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23995903013.webp', 'https://www.flickr.com/photos/zaragozaantigua/23995903013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20937, 'Apariciâ”œâ”‚n de la Virgen, s. XVI', '"Apariciâ”œâ”‚n de la Virgen a Santiago Zebedeo en Zaragoza", tabla gâ”œâ”‚tica flamenca, siglo XVI. En la vista figurada de la ciudad del fondo, aparece la Puerta del â”œÃ¼ngel. Fuente: eszaragoza.blogspot.com', 1550, 1500, 1599, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65614300, -0.87593500, '0101000020E61000000F7F4DD6A807ECBFEA3F6B7EFCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36718010784.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36718010784.webp', 'https://www.flickr.com/photos/zaragozaantigua/36718010784/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20945, 'Puerta del â”œÃ¼ngel 1813', 'Puerta de los Angelos. Edward Hawke Locker (dib.) y William Westall (lit.), 1824.', 1813, 1813, 1813, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65592000, -0.87600000, '0101000020E6100000D578E9263108ECBF6B65C22FF5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15002343922.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15002343922.webp', 'https://www.flickr.com/photos/zaragozaantigua/15002343922/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20959, 'Diputaciâ”œâ”‚n del Reino 1831', 'Puerta del salâ”œâ”‚n de Cortes en el palacio de la Diputaciâ”œâ”‚n del Reino de Zaragoza. Valentâ”œÂ¡n Carderera, entre 1831 y 1834. Lâ”œÃ­piz y aguada sobre papel. A la derecha, a lâ”œÃ­piz: "Demolido". "La Diputaciâ”œâ”‚n del General, conocida como Diputaciâ”œâ”‚n del Reino, vigente entre 1364 y 1707, nace como organismo encargado de recaudar y administrar el dinero que en las Cortes Generales de Monzâ”œâ”‚n de 1362 se habâ”œÂ¡a ofrecido al monarca Pedro IV. Los acontecimientos polâ”œÂ¡ticos irâ”œÃ­n dotando a la instituciâ”œâ”‚n de nuevas atribuciones, primero como â”œâ”‚rgano rector de la hacienda real, despuâ”œÂ®s asumiendo la polâ”œÂ¡tica del Reino en los periodos que separaban las reuniones de Cortes. Tambiâ”œÂ®n se ocupâ”œâ”‚ de controlar la paz interna y externa, arbitrar las rivalidades surgidas entre nobles y universidades, defender los fueros y privilegios del reino, y controlar el Justiciazgo mediante la elecciâ”œâ”‚n de sus lugartenientes. Tuvo su sede en un palacio situado en la Plaza de la Seo, conocido desde el siglo XV como Ã”Ã‡Â£casas de la Diputaciâ”œâ”‚nÃ”Ã‡Ã˜, espacio que compartiâ”œâ”‚ con la Real Audiencia y la Gobernaciâ”œâ”‚n General. A finales del siglo XV se produce una importante reforma en las instituciones aragonesas y la Diputaciâ”œâ”‚n quedarâ”œÃ­ bajo el control absoluto del monarca y, como consecuencia de las Ã”Ã‡Â£alteraciones del ReinoÃ”Ã‡Ã˜, en las Cortes de Tarazona de 1592 verâ”œÃ­ reducidas sus atribuciones. La llegada de los Borbones supuso una nueva organizaciâ”œâ”‚n del Reino y, a travâ”œÂ®s de los Decretos de Nueva Planta dictados por Felipe V, las instituciones aragonesas quedaron disueltas, entre ellas la Diputaciâ”œâ”‚n del Reino (1707)." Mâ”¬Â¬ Cruz Moreno Gajate. Archivo Diputaciâ”œâ”‚n Provincial de Zaragoza. En la lâ”œÃ­mina, portada renacentista de la entrada a las Cortes, con un macero en el umbral. El edificio se terminâ”œâ”‚ de construir en 1450 y sufriâ”œâ”‚ daâ”œâ–’os graves en 1809, siendo demolido en 1834. Fuente: "Viaje artâ”œÂ¡stico por Aragâ”œâ”‚n de Valentâ”œÂ¡n Carderera", Josâ”œÂ® Marâ”œÂ¡a Lanzarote Guiral, e Itziar Arana Cobos, IFC - Fundaciâ”œâ”‚n Lâ”œÃ­zaro Galdiano, 2013.', 1831, 1831, 1831, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65550900, -0.87563500, '0101000020E6100000697407B13305ECBFE99D0AB8E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15360842572.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15360842572.webp', 'https://www.flickr.com/photos/zaragozaantigua/15360842572/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21121, 'La Seo 1889', 'Imagen tomada bajo el arco del Arzobispo en el arranque de la calle del Sepulcro y centrada en el lienzo norte de la Seo donde destaca en primer tâ”œÂ®rmino el denominado "muro de la Parroquieta" donde posa un abigarrado grupo de varones de diversas edades y condiciones sociales.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65494600, -0.87534400, '0101000020E61000008FFE976BD102ECBFB1524145D5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31105192694.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31105192694.webp', 'https://www.flickr.com/photos/zaragozaantigua/31105192694/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21129, 'La Seo 1889', 'Imagen capturada desde cierta altura, posiblemente en el nâ”¬â•‘ 7 de la calle de la Lonja, y centrada en el neoclâ”œÃ­sico frontispicio y la barroca torre de la catedral de San Salvador o La Seo, recayentes a la homâ”œâ”‚nima plaza recientemente urbanizada. Entre el frontispicio y la torre, el cimborrio gâ”œâ”‚tico-mudâ”œÂ®jar. A la izquierda, el palacio Arzobispal y el arco del Arzobispo, detrâ”œÃ­s del que emerge al fondo la torrecilla de la iglesia de San Nicolâ”œÃ­s de Bari.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65509100, -0.87599000, '0101000020E6100000F2EF332E1C08ECBFB4739A05DAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41363224510.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41363224510.webp', 'https://www.flickr.com/photos/zaragozaantigua/41363224510/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21149, 'Ribera del Ebro c.1890', 'Paseo de la Ribera del Ebro. A la derecha, uno de los leones del puente de Piedra, el mâ”œÃ­s cercano al Pilar. Fuente: www.facebook.com/photo.php?fbid=10204473722256687&set...', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65639400, -0.87574200, '0101000020E6100000EA7937161406ECBF33A5F5B704D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15672875820.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15672875820.webp', 'https://www.flickr.com/photos/zaragozaantigua/15672875820/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21177, 'Cimborrio de la Seo 1890', 'Cimborrio mudâ”œÂ®jar (s.XIV) de la Catedral del Salvador, filigrana de Mahoma Ramâ”œÂ¡ en ladrillo, y rematado en una espadaâ”œâ–’a. Imagen capturada a cierta altura, desde la que fuera antigua plaza de San Bartolomâ”œÂ®, un espacio integrado en la irregular plaza de San Bruno, que da acceso a la calle del Sepulcro. Fuente visual: "Cimborrio del templo metropolitano de la Seo", en Ã”Ã‡Â£Zaragoza Artâ”œÂ¡stica, Monumental e Histâ”œâ”‚ricaÃ”Ã‡Ã˜, Anselmo y Pedro Gascâ”œâ”‚n de Gotor (1890-91).', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65497600, -0.87540700, '0101000020E61000002810768A5503ECBF1BD5E940D6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33446977324.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33446977324.webp', 'https://www.flickr.com/photos/zaragozaantigua/33446977324/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21209, 'Margen Izquierda 1905', 'AHPZ. Estudio Coyne. 1905. "Vista del râ”œÂ¡o Ebro y el puente de Piedra." Imagen, al fondo, de la iglesia de Altabâ”œÃ­s y, a la derecha, del Cuartel de San Lâ”œÃ­zaro. Una columna de negro humo delata la actividad, mâ”œÃ­s al fondo, de una locomotora en acciâ”œâ”‚n, por la Estaciâ”œâ”‚n del Norte.', 1905, 1905, 1905, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65618400, -0.87584800, '0101000020E6100000548B8862F206ECBF49145AD6FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14951043130.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14951043130.webp', 'https://www.flickr.com/photos/zaragozaantigua/14951043130/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21361, 'Plaza de La Seo 1900', 'Imagen capturada en la plaza de La Seo con una vista parcial del cortejo municipal salido del homâ”œâ”‚nimo templo durante la celebraciâ”œâ”‚n, posiblemente, de la festividad del patrâ”œâ”‚n de la ciudad. Abren el cortejo a la izquierda los timbaleros portadores del tapiz con el escudo de Zaragoza, seguidos de los clarineros, los alguaciles y los maceros. Al fondo, fachada del Palacio Arzobispal con detalle de su portada de ingreso principal.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65523800, -0.87584800, '0101000020E6100000548B8862F206ECBF588CBAD6DED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54788599605.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54788599605.webp', 'https://www.flickr.com/photos/zaragozaantigua/54788599605/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21369, 'El Ebro y la Seo 1918', 'Vista desde el Pilar del râ”œÂ¡o Ebro y la torre de la Seo, en 1918. Fuente: Zaragoza 1908-2008. FCC.', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65552700, -0.87555800, '0101000020E61000009109F8359204ECBF8F52094FE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15089676224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15089676224.webp', 'https://www.flickr.com/photos/zaragozaantigua/15089676224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21375, 'Vista desde La Seo 1918', 'Una abierta mirada hacia el Suroeste de la ciudad desde uno de los ocho vanos del antiguo alminar nuevo de la mezquita aljama de Saraqusta, acrecentado en altura tras la conquista cristiana, y revestido de ropajes barrocos en el s.XVII. A los pies, el caserâ”œÂ¡o del barrio de La Seo, con algunos nuevos edificios en el eje de Don Jaime I, como el nâ”¬â•‘ 37, remodelado a finales del s.XIX, el nâ”¬â•‘ 41, edificado recientemente sobre la demolida iglesia de Santiago, y el nâ”¬â•‘ 35, aâ”œâ•‘n en obras, con proyecto de Albiâ”œâ–’ana. Muy cerca, sobresale la octogonal câ”œâ•‘pula y la torre de la iglesia de la Exaltaciâ”œâ”‚n de la Sta. Cruz, y la cercana plaza a la que da nombre. Una mirada panorâ”œÃ­mica, de izquierda a derecha, seâ”œâ–’ala varios hitos fundamentales: la mole cupular de Santiago el Mayor, los torreones laterales de la Audiencia, la Casa de la Misericordia (entre tinieblas), la torre de San Felipe, las torrecillas y câ”œâ•‘pula de los Escolapios, la alta torre de San Pablo, aparentemente al lado de la câ”œâ•‘pula y torres de Sta. Isabel. Cierra la visual, junto al florâ”œâ”‚n decorativo de la torre desde la que miramos, la chimenea de la "Alcoholera Agrâ”œÂ¡cola del Pilar", antes de convertirse en la "Azucarera Agrâ”œÂ¡cola del Pilar", en la calle 29 de septiembre. Fuente: Instituto Amatller de Arte Hispâ”œÃ­nico (Arxiu Mas).', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65498300, -0.87590900, '0101000020E6100000C0B4A84F7207ECBFCE37A27BD6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15695294748.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15695294748.webp', 'https://www.flickr.com/photos/zaragozaantigua/15695294748/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21376, 'Cimborrio de la Seo 1918', 'Desde la torre de la Seo, imagen del Cimborrio mudâ”œÂ®jar (s.XIV) de la Catedral del Salvador, obra de Mahoma Ramâ”œÂ¡, en ladrillo, y rematado en una espadaâ”œâ–’a. A la izquierda, tras un callejeo por la calle del Sepulcro, visual de la torre de San Nicolâ”œÃ­s de Bari y del Real Monasterio de Comendadoras Canonesas de la Orden Militar y Pontificia del Santo Sepulcro. Fuente: Instituto Amatller de Arte Hispâ”œÃ­nico (Arxiu Mas).', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65482900, -0.87544000, '0101000020E6100000168733BF9A03ECBF77BCC96FD1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15728009238.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15728009238.webp', 'https://www.flickr.com/photos/zaragozaantigua/15728009238/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21382, 'Cimborrio de la Seo 1918', 'Habiendo ascendido algo mâ”œÃ­s en la torre de la Seo, nueva imagen del Cimborrio de la Catedral, obra de Mahoma Ramâ”œÂ¡, desde mâ”œÃ­s altura y â”œÃ­ngulo que permite una parcial pero muy interesante visual del antiguo barrio de la Seo. Asâ”œÂ¡, y la derecha, un poco a oscuras por estar en sombra, la reconocible puerta de la Aduana Vieja, en la plazuela del mismo nombre. Aunque ya fuera de plano, podremos seguir por la derecha, a travâ”œÂ®s de la calle de la Aduana Vieja, y llegar mentalmente a la Plaza del Reino, con todo o que ello supone. Torcemos hacia la izquierda, y nos metemos otra vez en la imagen por la calle del Chantre, algunos de cuyos edificios de viviendas asoman justo detrâ”œÃ­s del cimborrio de la Seo, ofreciâ”œÂ®ndonos sus modestas fachadas, en la abigarrada manzana de casas entre Chantre y Gavâ”œÂ¡n. Justo por aquâ”œÂ¡ pasa la actual San Vicente de Paâ”œâ•‘l, como por encima de las inmediatas calles de Silencio, Garro, Grillo... Si continuamos rectos, llegamos a la calle Conde Alperche, tras cruzar la calle del Sepulcro, que tiene un recoveco llamado calle de Esmir, donde se levanta el Palacio del mismo nombre. Un poco mâ”œÃ­s hacia la izquierda, la ribera, y el Ebro. Fuente: Instituto Amatller de Arte Hispâ”œÃ­nico (Arxiu Mas).', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65485900, -0.87545000, '0101000020E6100000F90FE9B7AF03ECBFE23E726BD2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15915590095.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15915590095.webp', 'https://www.flickr.com/photos/zaragozaantigua/15915590095/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21383, 'Vista Pilar 1910', '"Vista de la Catedral-Basâ”œÂ¡lica de Nostra Senyora del Pilar de Saragossa". 1910 Imagen de una tarjeta postal de la "Fototipia Castaâ”œâ–’eira y Alvarez" (Madrid), dedicada a Zaragoza. Desde la torre de la Seo, una visual interesante del cogollo urbano en torno a la Seo, la Lonja, y el Pilar, alcanzando la vista hasta el Puente del Ferrocarril, allâ”œÃ­ al fondo. Fuente: Ajuntament de Girona, Servei de Gestiâ”œâ”‚ Documental, Arxius i Publicacions.', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65498300, -0.87590900, '0101000020E6100000C0B4A84F7207ECBFCE37A27BD6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16223214726.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16223214726.webp', 'https://www.flickr.com/photos/zaragozaantigua/16223214726/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21406, 'La Lonja aâ”œâ–’os 10', 'Postal. Vista de la Lonja desde el puente de Piedra. Fuente: www.ebay.com/', 1910, 1910, 1919, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65640700, -0.87597800, '0101000020E6100000E17EC0030308ECBFC8EE022505D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25559094936.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25559094936.webp', 'https://www.flickr.com/photos/zaragozaantigua/25559094936/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21429, 'Ribera del Ebro c.1910', 'Imagen capturada desde la margen izquierda del Ebro, centrada en el tramo de la ribera donde destaca la fachada del complejo del palacio Arzobispal-Seminario diocesano. Detrâ”œÃ­s, el cimborrio y la torre de la catedral de la Seo. A la izquierda, la torre de San Carlos Borromeo sobresale por encima de la antigua casa de Ezmir. o Esmir. A la derecha, el final de la calle de Don Jaime I, con la Casa del Ayuntamiento y la Lonja, y el arranque del puente de Piedra. Por el paseo del Ebro transitan dos jardineras motoras en servicio en la lâ”œÂ¡nea "Circunvalaciâ”œâ”‚n", que coinciden en el desvâ”œÂ¡o que permitâ”œÂ¡a la continuidad del ramal que provenâ”œÂ¡a de la Magdalena (desde la izquierda), y el del Mercado (desde la derecha). Fuente: "Palacio Arzobispal y Torre de la Seo", postal nâ”¬â•‘ 39 de la serie "Zaragoza" de ediciâ”œâ”‚n Thomas, en www.ebay.com/', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65595400, -0.87538500, '0101000020E610000033164D672703ECBF17D7F84CF6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34079385040.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34079385040.webp', 'https://www.flickr.com/photos/zaragozaantigua/34079385040/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21444, 'Puente de Piedra c.1910', 'Imagen capturada en el arranque del puente de Piedra desde el paseo del Ebro, con el fondo del Seminario Metropolitano y el Palacio Arzobispal. En primer tâ”œÂ®rmino, medios de locomociâ”œâ”‚n a uâ”œâ–’a de caballerâ”œÂ¡a.', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65624000, -0.87590200, '0101000020E6100000200890A16307ECBFDC291DACFFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49915047058.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49915047058.webp', 'https://www.flickr.com/photos/zaragozaantigua/49915047058/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21506, 'Plaza de la Seo 1925', 'Miguel Faci Abad. 1920-1925. "Zaragoza. La plaza de la Seo desde el arco del Arzobispo". Imagen de la plaza de la Seo capturada desde la calle del Sepulcro, un poco antes de volandero arco del Arzobispo, entre el palacio arzobispal con el templo de la Seo. Es precisamente la inmediatez con el palacio lo que le da a la imagen una perspectiva interesante: asâ”œÂ¡, en lâ”œÂ¡nea recta, el palacio, la Lonja, las viviendas de la calle del Pilar, y el Pilar. La plaza de la Seo queda definida por el espacio abierto y arbolado de la izquierda, con la visual de la fuente de la Samaritana. Por encima de los â”œÃ­rboles sobresale el remate bulboso del peculiar establecimiento "El Pilar" (pintura, esculturas, artesanâ”œÂ¡as), ademâ”œÃ­s de otras viviendas entre esta plaza y la del Pilar. Escenas de la vida cotidiana animan el encuadre: una abuela con su nieta; un vendedor ambulante empujando su carrito del helao; dos "mozos de cuerda" (contratados para llevar cosas de carga); un carro a punto de llegar a Don Jaime I... Fuente visual: "Miguel y Gabriel Faci. Fotâ”œâ”‚grafos fundadores de la Real Sociedad Fotogrâ”œÃ­fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaciâ”œâ”‚n Provincial de Zaragoza, 1999.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65519200, -0.87565000, '0101000020E6100000BEC117265305ECBFE84CDA54DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15589492100.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15589492100.webp', 'https://www.flickr.com/photos/zaragozaantigua/15589492100/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21630, 'Pl. de la Seo c.1920', 'Imagen capturada en la plaza de la Seo durante el jueves despuâ”œÂ®s de la octava de Pentecostâ”œÂ®s y centrada en la catâ”œâ”‚lica salida en procesiâ”œâ”‚n de la custodia realizada por el platero Pedro Lameison a comienzos del siglo XVI, con aâ”œâ–’adidos posteriores. Al fondo, la barroca fachada que reviste el ingreso principal a la iglesia metropolitana del Salvador. A la izquierda, el desaparecido arco del Arzobispo o volado acceso al palacio arzobispal. En beneficio de todos, gratis et amore, hemos volteado horizontalmente la imagen original. Fuente visual: Francisco Gâ”œâ”‚rriz, Archivo Municipal de Zaragoza', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65509100, -0.87599000, '0101000020E6100000F2EF332E1C08ECBFB4739A05DAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38258355846.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38258355846.webp', 'https://www.flickr.com/photos/zaragozaantigua/38258355846/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21698, 'Paseo del Ebro 1931', 'En primer tâ”œÂ®rmino, coche participante en el III Gran Premio de Turismo organizado por el Moto Club de Cataluâ”œâ–’a un lluvioso 4 de junio de ese aâ”œâ–’o. Al fondo, el palacio de Ayerbe y el templo del Pilar. A la derecha y fuera de plano, el râ”œÂ¡o Ebro.', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65612200, -0.87602100, '0101000020E6100000B37E33315D08ECBFD31742CEFBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15473970246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15473970246.webp', 'https://www.flickr.com/photos/zaragozaantigua/15473970246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21710, 'Paseo de la Ribera 1933', '"El Canal Imperial i el riu Huerva (Saragossa)" El tâ”œÂ¡tulo (la fuente visual asâ”œÂ¡ lo cataloga) no se corresponde con la captura, salvo en que es Zaragoza: se trata de una imagen desde la margen izquierda del Ebro, junto al puente de Hierro, del paseo de la Ribera, con una buena visual de la tremenda fachada que entonces habâ”œÂ¡a, desde la basâ”œÂ¡lica concatedral, la casa de los Infantes, el palacio de los marqueses de Ayerbe, la Posada del Rey, La Lonja, el palacio Arzobispal, la torre y el cimborrio de la Catedral del Salvador en su Epifanâ”œÂ¡a, y el palacio de Esmir y la calle del conde de Alperche. Algunos de estos elementos, transformados, perduran. Otros, no. Fuente visual: Fotografâ”œÂ¡a de Gonzalo Reparaz Ruiz (cartotecadigital.icc.cat/)', 1933, 1933, 1933, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65596000, -0.87530100, '0101000020E6100000BDFE243E7702ECBFF9BD4D7FF6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17170406628.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17170406628.webp', 'https://www.flickr.com/photos/zaragozaantigua/17170406628/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21752, 'Cimborrio Seo 1930', '"Zaragoza. Câ”œâ•‘pula de la Seo" (sic). Imagen del Cimborrio de la Catedral capturada por Antâ”œâ”‚nio Passaporte en una de sus impagables visitas a la ciudad. Esta imagen resulta especialmente interesante, porque permite acotar en el tiempo el derribo del edificio de la "Aduana Vieja", o antigua Casa de hospedaje de la Diputaciâ”œâ”‚n del Reino para diputados foranos. Aunque la imagen tiene un fondo nebuloso que difumina los contornos, es perfectamente visible, a la derecha, el blanquâ”œÂ¡simo, y con regulares vanos, edificio del nuevo "Grupo Escolar Marcelino Lâ”œâ”‚pez Ornat", construido sobre buena parte del solar del antiguo palacio, en la esquina de la calle Palafox, a la derecha, que ademâ”œÃ­s ha sido ensanchada, y la entonces calle del Chantre.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65487900, -0.87539600, '0101000020E61000002D93E1783E03ECBF29EB3713D3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22204711298.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22204711298.webp', 'https://www.flickr.com/photos/zaragozaantigua/22204711298/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21766, 'Arco del Arzobispo 1932', 'Arco del Arzobispo y plaza de la Seo. Al fondo, la Lonja y el Pilar. Fuente visual: Foto Conrado Barlâ”œÂ®s, donada por Daniel Barlâ”œÂ®s y digitalizada por Josâ”œÂ® Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65526100, -0.87568800, '0101000020E61000001EFD2FD7A205ECBF11ACAA97DFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22622124093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22622124093.webp', 'https://www.flickr.com/photos/zaragozaantigua/22622124093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21776, 'La Seo 1932', 'Calle del Sepulcro y muros de la Seo. Fuente visual: Foto Conrado Barlâ”œÂ®s, donada por Daniel Barlâ”œÂ®s y digitalizada por Josâ”œÂ® Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65511700, -0.87538800, '0101000020E610000078F2E9B12D03ECBFDD06B5DFDAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22881366859.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22881366859.webp', 'https://www.flickr.com/photos/zaragozaantigua/22881366859/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21782, 'Râ”œÂ¡o Ebro 1932', 'Imagen capturada desde el puente del Pilar, con el râ”œÂ¡o Ebro, el puente de Piedra, y buena parte de la antigua fachada de la ciudad en su margen derecha, desde el barrio de La Seo, y hasta la basâ”œÂ¡lica concatedral. Fuente visual: Bildarchiv Foto Marburg, en www.bildindex.de/', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65606100, -0.87532400, '0101000020E6100000C8EC2C7AA702ECBF2D978DCEF9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23170416029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23170416029.webp', 'https://www.flickr.com/photos/zaragozaantigua/23170416029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23128, 'Monumento al Doctor Cerrada 2006', 'Foto: Guillermo Mestre. Estado del monumento al Doctor Cerrada del parque Primo de Rivera (1929), con el centauro Quirâ”œâ”‚n decapitado. En 2008, la escultura en piedra serâ”œÃ­ sustituida por una de bronce. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'UNIVERSIDAD', 41.63392500, -0.89683600, '0101000020E6100000BC033C69E1B2ECBFF38E537424D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31489401150.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31489401150.webp', 'https://www.flickr.com/photos/zaragozaantigua/31489401150/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21808, 'Calle del Sepulcro 1937', '"Estos moros que vemos deambular por las calles de Zaragoza son moros "de" Espaâ”œâ–’a, y vienen de la guerra, que para ser eminentemente popular necesitaba que los alfanjes moros se juntaran a nuestras espadas en la lucha contra el comunismo, en la que se ventila, nada mâ”œÃ­s y nada menos, el porvenir de la civilizaciâ”œâ”‚n". Miguel Alluâ”œÂ® Salvador (alcalde de Zaragoza 1927-29). En el dibujo, representaciâ”œâ”‚n de mercenarios soldados norteafricanos de los tabores de la Mehalla de Tetuâ”œÃ­n, llegados a Zaragoza en octubre de 1936, como refuerzo de guerra de los sublevados nacionalistas contra la repâ”œâ•‘blica democrâ”œÃ­tica. Aparecen ubicados de forma idealista delante del mudâ”œÂ®jar "Muro de la Parroquieta" de la iglesia del Salvador, y casi bajo el arco del Arzobispo, en el arranque de la calle del Sepulcro. Un surreal homenaje, sin pretenderlo, a aquellos otros moros que, siglos ha, y siendo indâ”œÂ¡genas, fueron expulsados, u obligados a convertirse a la verdadera religiâ”œâ”‚n. Fuente visual: Revista "Aragâ”œâ”‚n", SIPA, 1937.', 1937, 1937, 1937, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65516500, -0.87547300, '0101000020E610000004FEF0F3DF03ECBFEE3D5C72DCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28561213023.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28561213023.webp', 'https://www.flickr.com/photos/zaragozaantigua/28561213023/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21873, 'P.â”¬â•‘ del Ebro c.1932', 'Despejada y luminosa imagen capturada en el paseo del Ebro entre la Lonja y el puente de Piedra, con una interesante panorâ”œÃ­mica de la antigua fachada urbana en este tramo ribereâ”œâ–’o, desde la Lonja, con sus jardines y estanque, la posada de los Reyes, la gran casa de los Ayerbe, las casas de los Infantes y el templo del Pilar. Sobre el firme, a la izquierda, tramo de vâ”œÂ¡a de la tranviaria lâ”œÂ¡nea del Gâ”œÃ­llego tendido por unas obras en el puente de Piedra, de forma que el trayecto de vuelta se realizaba por el puente de Hierro. A la derecha, tendido de la lâ”œÂ¡nea de Circunvalaciâ”œâ”‚n. Fuente visual: Ediciones Arribas, AMZ. Desde el', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65614300, -0.87593500, '0101000020E61000000F7F4DD6A807ECBFEA3F6B7EFCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39599563500.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39599563500.webp', 'https://www.flickr.com/photos/zaragozaantigua/39599563500/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21896, 'Calle del Sepulcro c.1935', 'Inicio de la calle del Sepulcro flanqueado entre el muro mudâ”œÂ®jar de la Parroquieta de la Seo, a la izquierda, y el ilustrado muro del Palacio Arzobispal, cuyo homâ”œâ”‚nimo arco al fondo ofrece una vista que alcanza hasta la calle del Pilar, con el edificio de la Lonja esquinero con la calle de Don Jaime I, e incluso la difuminada silueta de la torre de Nuestra Seâ”œâ–’ora del Pilar del homâ”œâ”‚nimo templo, apuntando hacia arriba. Tras el arco, la plaza de La Seo. En primer tâ”œÂ®rmino, dos infantes atraâ”œÂ¡dos por el artilugio fotogrâ”œÃ­fico que captura la instantâ”œÃ­nea se distraen de los juegos con que otros, mâ”œÃ­s atentos, pasan el rato junto a la singular tracerâ”œÂ¡a mudâ”œÂ®jar que cierra la capilla del arzobispo Luna.', 1935, 1935, 1935, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65515000, -0.87550500, '0101000020E6100000DC80CF0F2304ECBFB9FC87F4DBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50762703831.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50762703831.webp', 'https://www.flickr.com/photos/zaragozaantigua/50762703831/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22076, 'Calle Pabostrâ”œÂ¡a 1951', 'Archivo Municipal. Archivo Juan Mora. 1951 Imagen de la calle Pabostrâ”œÂ¡a, capturada desde la calle Deâ”œÃ­n. A la izquierda, se abre la calle Lucero. El muro delimita al palacio de los Armijo. Al fondo, visual de la calle Dormer, con el palacio de la Maestranza bien soleado.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65411600, -0.87551500, '0101000020E6100000C00985083804ECBF2AE5B512BAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15573381458.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15573381458.webp', 'https://www.flickr.com/photos/zaragozaantigua/15573381458/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22080, 'Calle Lucero 1951', 'Archivo Municipal. Archivo Juan Mora. 1951 Imagen de la breve calle Lucero, capturada desde la calle Pabostria. Al fondo, la calle Don Juan de Aragâ”œâ”‚n. A la izquierda, el antiguo palacio de los Armijo.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65401200, -0.87578400, '0101000020E6100000A585CB2A6C06ECBF85984BAAB6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15758884675.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15758884675.webp', 'https://www.flickr.com/photos/zaragozaantigua/15758884675/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22085, 'Infantes Reales en plaza de la Seo 1951', 'Desde su llegada al Reino de Espaâ”œâ–’a para continuar sus estudios en 1950, los Infantes Juan Carlos y Alfonso de Borbâ”œâ”‚n realizaron diversos viajes tulelados por la geografâ”œÂ¡a peninsular (Madrid, Valencia, Sevilla...) para ir conociendo un paâ”œÂ¡s para ellos extraâ”œâ–’o. En octubre de 1951 vinieron a Zaragoza para visitar el Pilar y la Seo. En la imagen, los infantes Alfonso (10 aâ”œâ–’os de edad) y Juan Carlos (13 aâ”œâ–’os de edad) junto a la puerta de la Catedral del Salvador en su Epifanâ”œÂ¡a, en la plaza de la Seo, que se abre detrâ”œÃ­s de ellos, con el arbolado espacio central en torno a la fuente de la Samaritana, con el caracterâ”œÂ¡stico quiosco de prensa, y los bancos de sentarse. Entre el adoquinado, las vâ”œÂ¡as de la lâ”œÂ¡nea del tranvâ”œÂ¡a giran hacia el puente de Piedra y el Arrabal. A la derecha, la Lonja, y la iluminada esquina del Seminario Diocesano, a punto de trasladarse al nuevo recinto de Casablanca.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65519200, -0.87565000, '0101000020E6100000BEC117265305ECBFE84CDA54DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16335512123.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16335512123.webp', 'https://www.flickr.com/photos/zaragozaantigua/16335512123/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22112, 'Arco del Deâ”œÃ­n 1951', 'Imagen, entre claroscuros, capturada en la calle del Deâ”œÃ­n, con el Arco del mismo nombre de tenebrista fondo, antes de su radical reinvenciâ”œâ”‚n unos aâ”œâ–’os despuâ”œÂ®s. Es una de esas imâ”œÃ­genes que a finales de los aâ”œâ–’os 50 del pasado siglo se utilizaban para ilustrar la "Vieja Zaragoza", en cualquiera de sus acepciones, por contraposiciâ”œâ”‚n con la "Moderna". Fuente visual: Sebastiâ”œÃ­n Gâ”œâ”‚mez Cortâ”œÂ®s.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65430700, -0.87501700, '0101000020E61000008335CEA62300ECBF9E45EF54C0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22113512675.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22113512675.webp', 'https://www.flickr.com/photos/zaragozaantigua/22113512675/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22306, 'Puente de Piedra 1962', 'Imagen del Puente de Piedra capturada desde el paseo de la Ribera a la altura del emboque en la calle Don Jaime I. La arcada y el pilar de soporte son los mâ”œÃ­s prâ”œâ”‚ximos a la margen derecha del râ”œÂ¡o. Un par de motos, un tractor, y un autobâ”œâ•‘s de â”œÃ¼greda Automâ”œâ”‚vil, no alcanzan a colapsar el trâ”œÃ­fico, aunque unos aâ”œâ–’os despuâ”œÂ®s sâ”œÂ¡ serâ”œÃ­ posible. Los peatones, bien, gracias. Fuente: www.flickr.com/photos/madridx1306/1340434217/in/photostream/', 1962, 1962, 1962, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65636800, -0.87582800, '0101000020E61000008E791D71C806ECBF0A12DBDD03D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15620175827.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15620175827.webp', 'https://www.flickr.com/photos/zaragozaantigua/15620175827/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22332, 'Calle del Deâ”œÃ­n aâ”œâ–’os 60', 'Escena teatralizada de rondalla jotera a damas en balcâ”œâ”‚n, localizada en la calle del Deâ”œÃ­n, junto al pasaje arquitrabado desaparecido en los aâ”œâ–’os 70, con el arco del Deâ”œÃ­n al fondo.', 1960, 1960, 1969, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65430700, -0.87501700, '0101000020E61000008335CEA62300ECBF9E45EF54C0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18966133301.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18966133301.webp', 'https://www.flickr.com/photos/zaragozaantigua/18966133301/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22866, 'Plaza del Pilar 1987', 'Luis Mâ”œÂ¡nguez. 1987. Desde la torre de la Catedral del Salvador, una abierta vista desde la inmediata y arbolada plaza de la Seo, hasta la amplia plaza del Pilar, con sus diferentes sectores (isleta peatonal del monumento de Goya; isleta-aparcamiento frente al Ayuntamiento; plaza-aparcamiento del Gobierno Civil, a la izquierda; explanada peatonal frente al Pilar; isleta-aparcamiento de los cipreses, frente al monumento "A los hâ”œÂ®roes y mâ”œÃ­rtires de Zaragoza. Caâ”œÂ¡dos en la Cruzada de Liberaciâ”œâ”‚n 1936-1939". La circulaciâ”œâ”‚n rodada cuarteaba este gran espacio por todos los lados.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65498300, -0.87590900, '0101000020E6100000C0B4A84F7207ECBFCE37A27BD6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15665965000.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15665965000.webp', 'https://www.flickr.com/photos/zaragozaantigua/15665965000/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22879, 'Calle Lucero 1989', 'Imagen capturada desde el encuentro de las calles Pabostria y Lucero de las traseras de los restos en pie del antiguo palacio de la calle Don Juan de Aragâ”œâ”‚n nâ”¬â•‘ 7, otro ejemplo de la suerte que en esta ciudad han padecido numerosas casas-palacio renacentistas del XVI. Propiedad privada, es declarado en ruina en 1969, y piqueteado un par de aâ”œâ–’os despuâ”œÂ®s, salvo la fachada principal, y una parte de la secundaria. En 1979 se inician tareas de consolidaciâ”œâ”‚n de los restos, primero a cargo del Ministerio de Cultura, luego ya por el Ayuntamiento. Mucho mâ”œÃ­s tarde el edificio es reinventado para habilitar en â”œÂ®l la sede de la reinterpretada instituciâ”œâ”‚n medieval del "Justicia de Aragâ”œâ”‚n". Fuente: Ursula Heredia Lagunas, "Las casas palacio del siglo XVI en Zaragoza" Artigrama, 1989.', 1989, 1989, 1989, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65414800, -0.87569800, '0101000020E61000000186E5CFB705ECBF355F251FBBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17786108646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17786108646.webp', 'https://www.flickr.com/photos/zaragozaantigua/17786108646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22907, 'Plaza San Bruno 1989', 'Vista en altura de la excavaciâ”œâ”‚n arqueolâ”œâ”‚gica en el entorno de la calle Sepulcro y plaza San Bruno. Al fondo, traseras de la Seo y el Palacio Arzobispal. Se hallaron restos del foro y macellum (mercado) romanos, ademâ”œÃ­s del acceso al puerto fluvial. Fuente: "La legislaciâ”œâ”‚n y la gestiâ”œâ”‚n del patrimonio arqueolâ”œâ”‚gico de la ciudad de Zaragoza", Raâ”œâ•‘l Lâ”œâ”‚pez Villa, 2009.', 1989, 1989, 1989, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65509300, -0.87492600, '0101000020E61000006D718DCF64FFEBBF556B6116DAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22030739371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22030739371.webp', 'https://www.flickr.com/photos/zaragozaantigua/22030739371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23010, 'La Seo 1992', 'Vista del lado sur de la Seo, con la puerta de la calle Pabostrâ”œÂ¡a arriba a la izquierda. Las excavaciones arqueolâ”œâ”‚gicas de su subsuelo muestran la cimentaciâ”œâ”‚n del templo tiberiano del foro (siglo I). Fuente: Nuevos datos para el conocimiento del foro de Caesaraugusta, Empâ”œâ•‘ries 51, 1998.', 1992, 1992, 1992, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65456200, -0.87596800, '0101000020E6100000FDF50A0BEE07ECBF289A07B0C8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31582810403.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31582810403.webp', 'https://www.flickr.com/photos/zaragozaantigua/31582810403/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23208, 'Calle Pabostrâ”œÂ¡a 2010', 'Recreaciâ”œâ”‚n mediante montaje fotogrâ”œÃ­fico e infografâ”œÂ¡a de la esquina entre las calles del Deâ”œÃ­n (derecha) y de la Pabostrâ”œÂ¡a. Se trata de una propuesta del grupo municipal de Izquierda Unida en 2010, consistente en convertir la zona en una nueva plaza, eliminando los muros que separan estas calles de un solar sin uso, perteneciente al arzobispado. Estâ”œÃ­ situado en las traseras del Museo de Tapices de la Seo, en los terrenos del antiguo horno de pan de la catedral. La respuesta de los propietarios no se hizo esperar: ese solar serâ”œÃ­ utilizado para ampliar el citado museo, "prâ”œâ”‚ximamente". Fuente visual: Izquierda Unida de Aragâ”œâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65420900, -0.87552800, '0101000020E6100000E76ED74B5304ECBFDBDFD91EBDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33157073460.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33157073460.webp', 'https://www.flickr.com/photos/zaragozaantigua/33157073460/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23237, 'Mezquita mayor', 'Aspecto de la mezquita-aljama de Saraqusta hacia 1050. Dibujo de J. A. Pâ”œÂ®rez Casas sobre datos de B. Cabaâ”œâ–’ero, J. L. Corral y J. A. Pâ”œÂ®rez Casas. Libro Historia de cuatro ciudades', NULL, NULL, NULL, NULL, 'CASCO HISTâ”œÃ´RICO', 41.65458900, -0.87576400, '0101000020E6100000DE7360394206ECBF22A98592C9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14814477377.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14814477377.webp', 'https://www.flickr.com/photos/zaragozaantigua/14814477377/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23239, 'Mezquita Aljama', 'Zaragoza 1118, Mezquita Aljama. Javier Peâ”œâ–’a. "Hanas ibn cAbd Allah as-Sancâ”œÃ­ni construyâ”œâ”‚ la mezquita de la ciudad y levantâ”œâ”‚ su mihrab. Cuando se hizo una ampliaciâ”œâ”‚n de la mezquita-aljama, fue demolido el muro meridional, respetando el mihrab. Excavaron por debajo de â”œÂ®l y lo levantaron sobre dos grandes vigas de madera bajo las cuales colocaron unas columnas tumbadas con el fin de trasladarlo de sitio. Tiraron luego de las dos vigas por medio de cables pero el mismo dâ”œÂ¡a en que se hizo comenzâ”œâ”‚ a agrietarse el mihrab. Al dâ”œÂ¡a siguiente lo aseguraron con cables y volvieron a correrlo hasta el lugar en que hoy sigue emplazado. Por encima de â”œÂ®l y a sus lados construyeron el edificio que lo recubre".(Ahmad ibn cumar al cudri, 393/1003 - 478/1085). "En su mezquita hay un mihrab de un solo bloque de mâ”œÃ­rmol blanco que no existe en la tierra otro como â”œÂ®ste". (Az-Zuhri). En la imagen, reconstrucciâ”œâ”‚n idealizada de la mezquita-aljama de Saraqusta tras la ampliaciâ”œâ”‚n ordenada por Mundir I, primer sultâ”œÃ­n, del zagrâ”œÂ¡ reino de Saraqusta (1018-1022). Asâ”œÂ¡ la encontraron los invasores cristianos.', NULL, NULL, NULL, NULL, 'CASCO HISTâ”œÃ´RICO', 41.65458900, -0.87576400, '0101000020E6100000DE7360394206ECBF22A98592C9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14980608716.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14980608716.webp', 'https://www.flickr.com/photos/zaragozaantigua/14980608716/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23243, 'Carlomagno 780', 'La elaboraciâ”œâ”‚n a finales del siglo XI (1180-1190) del poema â”œÂ®pico titulado "Cantar de Roldâ”œÃ­n", supuso un desafâ”œÂ¡o para su-s autor-es, que se vieron en el brete de tener que relatar con la debida precisiâ”œâ”‚n los heroicos eventos desarrollados cuatro siglos antes, en los aâ”œâ–’os 778-780, durante la incursiâ”œâ”‚n peninsular del rey Carlos, que desde el reino de los Francos le trajo hasta la ciudad de Saraqusta. Los cronistas tuvieron que torcer un poco la realidad, parece ser, como ejemplifica el dibujo de la imagen, donde se ilustra la imaginada sumisiâ”œâ”‚n de la ciudad, representada por "Braslimonda", esposa del "monarca" musulmâ”œÃ­n del momento (denominado "Farnagâ”œÃ­n"), ante el rey de los Francos, Carlos, que luego serâ”œÂ¡a llamado Karl der Groâ”œÆ’e (Carlomagno). De tener algâ”œâ•‘n viso de realismo (que no tiene ninguno), esta escena se tendrâ”œÂ¡a que haber escenificado en la puerta norte, o del Puente. En el "Rollan a Saragossa", otro poema provenzal del gâ”œÂ®nero â”œÂ®pico, Roldâ”œÃ­n mantiene en la Saraqusta islâ”œÃ­mica unos encuentros amorosos con la reina Braslimonda, ciertamente tambiâ”œÂ®n â”œÂ®picos, que hacen que al rey Farnagâ”œÃ­n se lo lleven los demonios. No digas que fue un sueâ”œâ–’o. Fuente visual: Biblioteca Universitaria de Heidelberg (www.ub.uni-heidelberg.de/)', NULL, NULL, NULL, NULL, 'CASCO HISTâ”œÃ´RICO', 41.65614300, -0.87593500, '0101000020E61000000F7F4DD6A807ECBFEA3F6B7EFCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25100246541.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25100246541.webp', 'https://www.flickr.com/photos/zaragozaantigua/25100246541/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23104, 'Calle Gonzalo Calamita 2006', 'A comienzos del siglo XXI, el mal estado de las consultas del Hospital Universitario Miguel Servet, asâ”œÂ¡ como las necesidades de Traumatologâ”œÂ¡a, y el incremento de actividad hospitalaria, hicieron necesario plantear una soluciâ”œâ”‚n global. Inmediato, aunque al otro lado de la calle Gonzalo Calamita, estaba el viejo y desocupado edificio de la Mutualidad General de Funcionarios Civiles del Estado (MUFACE), sobre mâ”œÃ­s de 21000 metros cuadrados. Respetando la estructura, fachadas y cubiertas preexistentes, fue totalmente remodelado para albergar las nuevas consultas externas del Hospital General, de Traumatologâ”œÂ¡a y de Maternidad. Las obras comenzaron en 2004, y en el momento de capturar esta imagen, se acababa de instalar la pasarela sobrevolada de hierro para conectar el hospital (a la derecha) con el remodelado anexo (izquierda), mediante un viaducto a 4,5 metros de altura del suelo, de 38 metros de largo, una altura de 5,38 metros y 3,80 metros de ancho. Fuente: sectorzaragozados.salud.aragon.es/', 2006, 2006, 2006, 'Siglo XXI', 'UNIVERSIDAD', 41.63424300, -0.90070600, '0101000020E610000084F3A96395D2ECBFC45BE7DF2ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24322565039.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24322565039.webp', 'https://www.flickr.com/photos/zaragozaantigua/24322565039/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23440, 'Casa Armijo 1971', 'Denominada en â”œÂ®poca reciente "Casa Armijo" por el nombre de â”œâ•‘ltima familia que la poseyâ”œâ”‚, estâ”œÃ­ edificada en un solar de varias casas vendidas en 1147 a la Seo por el matrimonio Ponce de Fredalez y Estefanâ”œÂ¡a, destinadas a vivienda de dignidades capitulares. Esta, en concreto, fue vivienda del Arcipreste de la Seo. En 1878, Francisco de Armijo reformâ”œâ”‚ el edificio. En 1971, la Direcciâ”œâ”‚n General de Bellas Artes paralizâ”œâ”‚ el derribo ya iniciado de la casa, conservâ”œÃ­ndose la fachada a Don Juan de Aragâ”œâ”‚n, parte de la recayente a Lucero y sus correspondientes crujâ”œÂ¡as que rodean el patio. En 1979 el Ministerio de Cultura acometiâ”œâ”‚ obras de consolidaciâ”œâ”‚n del edificio con carâ”œÃ­cter de urgencia. En 1984 la Alcaldâ”œÂ¡a-Presidencia del Ayuntamiento aprobâ”œâ”‚ obras de carâ”œÃ­cter urgente (apuntalamientos y consolidaciones). Estas obras fueron dirigidas por la arquitecta municipal â”œÃœrsula Heredia Lagunas, y terminadas en 1989. Posteriormente, los arquitectos Garcâ”œÂ¡a Elorza y Fernandez Ramirez, reinventaban el edificio y lo habilitaban para Sede de la Instituciâ”œâ”‚n "Justicia de Aragâ”œâ”‚n". Mâ”œÃ­s tarde, se instalaron en el edificio dos techumbres mudâ”œÂ®jares procedentes del derribo de un inmueble en calle Cinegio nâ”¬â•‘ 5. En la imagen, el edificio reciâ”œÂ®n salvado de la piqueta total, visto desde la calle Don Juan de Aragâ”œâ”‚n. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1971, 1971, 1971, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65389800, -0.87575200, '0101000020E6100000CD02ED0E2906ECBFBC75FEEDB2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14888177222.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14888177222.webp', 'https://www.flickr.com/photos/zaragozaantigua/14888177222/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23465, 'Casa Armijo 1971', 'Vista del derribo de Casa Armijo, palacio renacentista entre las calles de Don Juan de Aragâ”œâ”‚n, Lucero y Pabostrâ”œÂ¡a. Tras conservarse la fachada al paralizarse este derribo, se reconstruye como "Palacio del Justicia" dando sede a esta instituciâ”œâ”‚n desde los aâ”œâ–’os noventa. Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1971, 1971, 1971, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65397800, -0.87572000, '0101000020E6100000F67F0EF3E505ECBFD926158DB5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23140686302.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23140686302.webp', 'https://www.flickr.com/photos/zaragozaantigua/23140686302/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23481, 'Casa de Armijo 1985', 'Imagen centrada en las ruinosas traseras de la casa denominada de Armijo, que fuera medieval residencia de dignidades capitulares de la Seo, cuya fachada e ingreso principal era por la calle de Don Juan de Aragâ”œâ”‚n (al fondo de la imagen). La captura se ha realizado antes de que el Ayuntamiento acometiera obras de apuntalamiento y consolidaciâ”œâ”‚n del edificio. A la derecha, fuera de plano, la calle Lucero conducâ”œÂ¡a a la de la Pabostrâ”œÂ¡a. Fuente visual: AMZ.', 1985, 1985, 1985, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65403800, -0.87567500, '0101000020E6100000F697DD938705ECBFAE2B6684B7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39825805542.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39825805542.webp', 'https://www.flickr.com/photos/zaragozaantigua/39825805542/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23490, 'Plaza de La Seo c.1889', 'Imagen capturada en la plaza de La Seo, recientemente reurbanizada, y centrada en la fachada del dieciochesco Palacio Arzobispal. A la izquierda, el Seminario Conciliar Metropolitano inaugurado oficialmente en 1848 y construido sobre los restos del antiguo Palacio de la Diputaciâ”œâ”‚n del Reino, que para ello fue terminado de derribar. A la derecha, el Arco del Arzobispo y vista parcial de la fachada del ingreso principal a la catedral de la Seo.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65530200, -0.87582700, '0101000020E610000077853E58C606ECBF6F8099EFE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50103973057.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50103973057.webp', 'https://www.flickr.com/photos/zaragozaantigua/50103973057/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23496, 'P.â”¬â•‘ de Echegaray y Caballero 1971', 'Imagen capturada en el paseo de Echegaray y Caballero y centrada en la opacada fachada ribereâ”œâ–’a del palacio Arzobispal, construido en terrenos graciosamente regalados a la iglesia por Alfonso I "el Batallador", del que a la izquierda emerge la barroca torre del templo de San Salvador. A la siniestra comienza el solar de la antigua y ya derribada notable casa de los Almonacid/Esmir, cuya desapariciâ”œâ”‚n incluyâ”œâ”‚ ademâ”œÃ­s el derribo del torreâ”œâ”‚n que flanqueaba por ese lado las dependencias arzobispales. A la derecha se nos muestra el inmueble que acogiera el Seminario metropolitano, ocupado en la fecha por diversas secciones de la Acciâ”œâ”‚n Catâ”œâ”‚lica Espaâ”œâ–’ola (Consejo Diocesano, Juventud Femenina, Juventud Masculina, Câ”œÃ­ritas Diocesana, Consejo Diocesano de Hombres...) Ante ella figura la estaciâ”œâ”‚n de servicio "N.â”¬Â¬ S.â”¬Â¬ del Pilar", desde donde a finales del mes de diciembre su trabajador Francisco Jimâ”œÂ®nez Lacarra contemplarâ”œÂ¡a câ”œâ”‚mo se precipitaba en el râ”œÂ¡o Ebro un autobâ”œâ•‘s de emigrantes. En el centro de la imagen un cartel publicitario anuncia a la petrolera norteamericana Caltex Oil S.A.E. Hacia la derecha, fuera de plano, se estacionaban los autobuses que conectaban Zaragoza con las localidades de San Juan de Mozarrifar, Villanueva de Gâ”œÃ­llego, Novillas y Huesca.', 1971, 1971, 1971, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65569500, -0.87510800, '0101000020E610000098F90E7EE200ECBF4B9352D0EDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54273489927.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54273489927.webp', 'https://www.flickr.com/photos/zaragozaantigua/54273489927/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
