INSERT INTO public.photos VALUES (23954, 'Jesâ”œâ•‘s atado c.1963', '"Jesâ”œâ•‘s atado a la columna" pasa bajo el arco del Arzobispo, en la plaza de la Seo de Zaragoza. La escultura es de Josâ”œÂ® Bueno, para la cofradâ”œÂ¡a del mismo nombre, que le acompaâ”œâ–’a caracterizada.', 1963, 1963, 1963, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65521100, -0.87564600, '0101000020E610000063F19BC24A05ECBF5F7D3CF4DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14791738670.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14791738670.webp', 'https://www.flickr.com/photos/zaragozaantigua/14791738670/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23975, 'Timbaleros y clarineros 1974', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 16/04/1974. Maceros, ujieres, timbaleros y clarineros son protocolarias figuras municipales para dar empaque a los actos mâ”œÃ­s solemnes del Ayuntamiento. Los maceros representan el poder y la autoridad y portan las mazas como seâ”œâ–’al de ello. Las mazas municipales datan del siglo XVIII y son obra del platero zaragozano Estrada. Sus antecedentes fueron los alguaciles, con funciones de anunciar y proteger a las autoridades locales. Clarineros y timbaleros quedan como reminiscencia de los heraldos del siglo XVI, con la misiâ”œâ”‚n de hacer notar musicalmente que la ciudad estâ”œÃ­ presente en el acto en el que participan. Cuatro son sus piezas mâ”œÃ­s recurrentes: la "Marcha de la ciudad", de tiempos de Juan II de Aragâ”œâ”‚n (1458-1479); el "Saludo al Ayuntamiento"; la "Marcha Regia"; y "el Pregâ”œâ”‚n". En la imagen, timbaleros y clarineros (con trompeta), junto con dos portaestandartes con el escudo herâ”œÃ­ldico de la ciudad, en un acto oficial en la Catedral de La Seo.', 1974, 1974, 1974, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65463400, -0.87558800, '0101000020E61000003CA41820D104ECBFC26C020CCBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15227857989.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15227857989.webp', 'https://www.flickr.com/photos/zaragozaantigua/15227857989/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
